'use server';

import { headers } from 'next/headers';
import { redirect } from 'next/navigation';
import { auth } from '@repo/auth/server';

/**
 * Destroys the better-auth session server-side and redirects to the canonical
 * sign-in route (Slice 2: explicit sign-out server action).
 */
export async function signOutAction() {
  const h = await headers();
  await auth.api.signOut({ headers: h });
  redirect('/');
}

export const dynamic = 'force-dynamic';

import { headers } from 'next/headers';
import { NextResponse } from 'next/server';
import { requireUser } from '@repo/auth/guards';
import { db, users, eq, sql } from '@repo/db';
import { UpdateConsentRequestSchema } from '@repo/contracts';

export async function GET() {
  const userResult = await requireUser(await headers());
  if (userResult.isErr()) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const userId = userResult.unwrap().id;
  const [row] = await db
    .select({
      marketingConsent: users.marketingConsent,
      productUpdatesConsent: users.productUpdatesConsent,
      consentUpdatedAt: users.consentUpdatedAt,
    })
    .from(users)
    .where(eq(users.id, userId))
    .limit(1);

  if (!row) {
    return NextResponse.json({ error: 'User not found' }, { status: 404 });
  }

  return NextResponse.json({
    marketingConsent: row.marketingConsent,
    productUpdatesConsent: row.productUpdatesConsent,
    consentUpdatedAt: row.consentUpdatedAt ? row.consentUpdatedAt.toISOString() : null,
  });
}

export async function POST(request: Request) {
  const userResult = await requireUser(await headers());
  if (userResult.isErr()) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const parseResult = UpdateConsentRequestSchema.safeParse(await request.json());
  if (!parseResult.success) {
    return NextResponse.json(
      { error: 'Validation failed', details: parseResult.error.flatten().fieldErrors },
      { status: 400 },
    );
  }

  const { marketingConsent, productUpdatesConsent } = parseResult.data;
  await db.execute(sql`
    update users
    set marketing_consent = ${marketingConsent},
        product_updates_consent = ${productUpdatesConsent},
        consent_updated_at = now()
    where id = ${userResult.unwrap().id}
  `);

  return NextResponse.json({
    ok: true,
    message: 'Consent settings updated',
  });
}

export const dynamic = 'force-dynamic';

import { headers } from 'next/headers';
import { NextResponse } from 'next/server';
import { requireUser } from '@repo/auth/guards';
import { auth } from '@repo/auth/server';
import { db, users, eq } from '@repo/db';
import { DeleteAccountRequestSchema } from '@repo/contracts';
import { sendAccountDeletionNotice } from '@repo/mail';

export async function POST(request: Request) {
  const requestHeaders = await headers();
  const userResult = await requireUser(requestHeaders);
  if (userResult.isErr()) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const parseResult = DeleteAccountRequestSchema.safeParse(await request.json());
  if (!parseResult.success) {
    return NextResponse.json(
      { error: 'Validation failed', details: parseResult.error.flatten().fieldErrors },
      { status: 400 },
    );
  }

  const user = userResult.unwrap();

  await sendAccountDeletionNotice({ to: user.email });
  await db.delete(users).where(eq(users.id, user.id));
  await auth.api.signOut({ headers: requestHeaders });

  return NextResponse.json({
    ok: true,
    message: 'Account deleted',
  });
}

export const dynamic = 'force-dynamic';

import { headers } from 'next/headers';
import { NextResponse } from 'next/server';
import { requireUser } from '@repo/auth/guards';
import { db, users, accounts, and, eq } from '@repo/db';
import { UpdateEmailRequestSchema } from '@repo/contracts';
import { sendEmailChangeNotice } from '@repo/mail';

export async function POST(request: Request) {
  const requestHeaders = await headers();
  const userResult = await requireUser(requestHeaders);
  if (userResult.isErr()) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const parseResult = UpdateEmailRequestSchema.safeParse(await request.json());
  if (!parseResult.success) {
    return NextResponse.json(
      { error: 'Validation failed', details: parseResult.error.flatten().fieldErrors },
      { status: 400 },
    );
  }

  const user = userResult.unwrap();
  const { newEmail } = parseResult.data;

  await db
    .update(users)
    .set({ email: newEmail })
    .where(eq(users.id, user.id));
  await db
    .update(accounts)
    .set({ accountId: newEmail })
    .where(and(eq(accounts.userId, user.id), eq(accounts.providerId, 'credential')));

  await sendEmailChangeNotice({
    to: user.email,
    newEmail,
  });

  return NextResponse.json({
    ok: true,
    message: 'Email updated',
  });
}

export const dynamic = 'force-dynamic';

import { headers } from 'next/headers';
import { NextResponse } from 'next/server';
import { requireUser } from '@repo/auth/guards';
import {
  db,
  users,
  sessions,
  creditTransactions,
  projects,
  eq,
  desc,
} from '@repo/db';
import { sendPersonalDataExportReady } from '@repo/mail';
import {
  PersonalDataExportResponseSchema,
  type PersonalDataExportResponse,
} from '@repo/contracts';

export async function GET() {
  const userResult = await requireUser(await headers());
  if (userResult.isErr()) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const user = userResult.unwrap();
  const [userRow] = await db.select().from(users).where(eq(users.id, user.id)).limit(1);
  if (!userRow) {
    return NextResponse.json({ error: 'User not found' }, { status: 404 });
  }

  const userSessions = await db
    .select()
    .from(sessions)
    .where(eq(sessions.userId, user.id))
    .orderBy(desc(sessions.createdAt));
  const creditRows = await db
    .select()
    .from(creditTransactions)
    .where(eq(creditTransactions.userId, user.id))
    .orderBy(desc(creditTransactions.createdAt));
  const projectRows = await db
    .select()
    .from(projects)
    .where(eq(projects.userId, user.id))
    .orderBy(desc(projects.createdAt));

  const payload: PersonalDataExportResponse = {
    generatedAt: new Date().toISOString(),
    user: {
      id: userRow.id,
      email: userRow.email,
      name: userRow.name,
      createdAt: userRow.createdAt.toISOString(),
      updatedAt: userRow.updatedAt.toISOString(),
      marketingConsent: userRow.marketingConsent,
      productUpdatesConsent: userRow.productUpdatesConsent,
      consentUpdatedAt: userRow.consentUpdatedAt ? userRow.consentUpdatedAt.toISOString() : null,
    },
    sessions: userSessions.map((row) => ({
      token: row.token,
      ipAddress: row.ipAddress ?? null,
      userAgent: row.userAgent ?? null,
      createdAt: row.createdAt.toISOString(),
      expiresAt: row.expiresAt.toISOString(),
      current: false,
    })),
    credits: creditRows.map((row) => ({
      id: row.id,
      type: row.type,
      amount: row.amount,
      balanceAfter: row.balanceAfter,
      createdAt: row.createdAt.toISOString(),
    })),
    projects: projectRows.map((row) => ({
      id: row.id,
      name: row.name,
      createdAt: row.createdAt.toISOString(),
      updatedAt: row.updatedAt.toISOString(),
    })),
  };

  const parseResult = PersonalDataExportResponseSchema.safeParse(payload);
  if (!parseResult.success) {
    return NextResponse.json({ error: 'Failed to build export payload' }, { status: 500 });
  }

  await sendPersonalDataExportReady({ to: user.email });

  return new NextResponse(JSON.stringify(parseResult.data, null, 2), {
    status: 200,
    headers: {
      'content-type': 'application/json; charset=utf-8',
      'content-disposition': 'attachment; filename="personal-data-export.json"',
    },
  });
}

export const dynamic = 'force-dynamic';

import { headers } from 'next/headers';
import { NextResponse } from 'next/server';
import { requireUser } from '@repo/auth/guards';
import { auth } from '@repo/auth/server';
import { UpdatePasswordRequestSchema } from '@repo/contracts';
import { sendPasswordChangeNotice } from '@repo/mail';

export async function POST(request: Request) {
  const requestHeaders = await headers();
  const userResult = await requireUser(requestHeaders);
  if (userResult.isErr()) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const parseResult = UpdatePasswordRequestSchema.safeParse(await request.json());
  if (!parseResult.success) {
    return NextResponse.json(
      { error: 'Validation failed', details: parseResult.error.flatten().fieldErrors },
      { status: 400 },
    );
  }

  const { currentPassword, newPassword, revokeOtherSessions } = parseResult.data;
  try {
    await auth.api.changePassword({
      headers: requestHeaders,
      body: {
        currentPassword,
        newPassword,
        revokeOtherSessions,
      },
    });
  } catch {
    return NextResponse.json(
      { error: 'Current password is invalid or operation failed' },
      { status: 400 },
    );
  }

  await sendPasswordChangeNotice({
    to: userResult.unwrap().email,
  });

  return NextResponse.json({
    ok: true,
    message: 'Password updated',
  });
}

export const dynamic = 'force-dynamic';

import { headers } from 'next/headers';
import { NextResponse } from 'next/server';
import { requireSession } from '@repo/auth/guards';
import { db, sessions, eq, and, desc } from '@repo/db';
import {
  RevokeSessionRequestSchema,
  type UserSession,
} from '@repo/contracts';

export async function GET() {
  const sessionResult = await requireSession(await headers());
  if (sessionResult.isErr()) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const current = sessionResult.unwrap();
  const currentToken = current.session.token;

  const rows = await db
    .select()
    .from(sessions)
    .where(eq(sessions.userId, current.user.id))
    .orderBy(desc(sessions.createdAt));

  const items: UserSession[] = rows.map((row) => ({
    token: row.token,
    ipAddress: row.ipAddress ?? null,
    userAgent: row.userAgent ?? null,
    createdAt: row.createdAt.toISOString(),
    expiresAt: row.expiresAt.toISOString(),
    current: row.token === currentToken,
  }));

  return NextResponse.json({ sessions: items });
}

export async function DELETE(request: Request) {
  const sessionResult = await requireSession(await headers());
  if (sessionResult.isErr()) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const parseResult = RevokeSessionRequestSchema.safeParse(await request.json());
  if (!parseResult.success) {
    return NextResponse.json(
      { error: 'Validation failed', details: parseResult.error.flatten().fieldErrors },
      { status: 400 },
    );
  }

  const token = parseResult.data.token;
  const userId = sessionResult.unwrap().user.id;

  await db
    .delete(sessions)
    .where(and(eq(sessions.userId, userId), eq(sessions.token, token)));

  return NextResponse.json({
    ok: true,
    message: 'Session revoked',
  });
}

/**
 * better-auth API route handler
 *
 * This route mounts the better-auth handler at /api/auth/[...all].
 * All auth operations (sign-in, sign-up, sign-out, session) are handled here.
 *
 * No business logic — just forwards to auth.handler per 76-better-auth.mdc §2.
 */

import { auth, toNextJsHandler } from '@repo/auth/server';

export const { GET, POST } = toNextJsHandler(auth);

/**
 * Credits Info API Route
 *
 * Thin HTTP adapter layer.
 */

export const dynamic = 'force-dynamic';

import { NextResponse } from 'next/server';
import { headers } from 'next/headers';
import { requireUser } from '@repo/auth/guards';
import { DrizzleCreditsRepository } from '@infrastructure/persistence/credits-repository';
import { toNextErrorResponse, catchUnknownError } from '@shared/http';

export async function GET() {
  try {
    const userResult = await requireUser(await headers());
    if (userResult.isErr()) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }
    const userId = userResult.unwrap().id;

    const creditsRepository = new DrizzleCreditsRepository();

    const balanceResult = await creditsRepository.getBalance(userId);
    if (balanceResult.isErr()) {
      return toNextErrorResponse(balanceResult.error);
    }
    const balance = balanceResult.unwrap();

    const transactionsResult = await creditsRepository.getTransactionHistory(userId, 50);
    if (transactionsResult.isErr()) {
      return toNextErrorResponse(transactionsResult.error);
    }
    const transactions = transactionsResult.unwrap();

    return NextResponse.json({
      creditBalance: balance.amount,
      graceUsed: balance.graceUsed,
      starterCreditsGranted: false,
      recentTransactions: transactions,
    });
  } catch (error: unknown) {
    return catchUnknownError(error, 'Failed to fetch credits');
  }
}

export const dynamic = 'force-dynamic'

import { NextRequest, NextResponse } from 'next/server'
import { headers } from 'next/headers'
import { requireUser } from '@repo/auth/guards'
import {
  db,
  milestoneFeedback,
  projects,
  eq,
  and,
  or,
  isNull,
  desc,
  type MilestoneFeedbackInsert,
} from '@repo/db'
import {
  MilestoneFeedbackSubmitRequestSchema,
  MilestoneFeedbackRowDTOSchema,
  MilestoneFeedbackDuplicateResponseSchema,
} from '@repo/contracts/feedback/submit'
import { err, ok } from '@repo/result'
import { ExternalServiceError } from '@shared/errors/application-error'
import { CaptureMilestoneFeedbackUseCase } from '@/src/application/feedback/capture-milestone-feedback-usecase'

export async function POST(request: NextRequest) {
  try {
    const userResult = await requireUser(headers())
    if (userResult.isErr()) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    const userId = userResult.unwrap().id

    const rawBody = await request.json().catch(() => null)
    const parsed = MilestoneFeedbackSubmitRequestSchema.safeParse(rawBody)
    if (!parsed.success) {
      return NextResponse.json(
        { error: 'Invalid input', details: parsed.error.flatten() },
        { status: 400 }
      )
    }

    const useCase = new CaptureMilestoneFeedbackUseCase({
      isProjectOwnedByUser: async (projectId: string, ownerUserId: string): Promise<boolean> => {
        const [project] = await db
          .select({ id: projects.id })
          .from(projects)
          .where(and(eq(projects.id, projectId), eq(projects.userId, ownerUserId)))
          .limit(1)
        return !!project
      },
      findDuplicate: async (
        ownerUserId: string,
        projectId: string,
        milestoneType: string,
        prdVersionId: string | null
      ): Promise<boolean> => {
        const [existing] = await db
          .select({ id: milestoneFeedback.id })
          .from(milestoneFeedback)
          .where(
            and(
              eq(milestoneFeedback.userId, ownerUserId),
              eq(milestoneFeedback.projectId, projectId),
              eq(milestoneFeedback.milestoneType, milestoneType),
              prdVersionId
                ? eq(milestoneFeedback.prdVersionId, prdVersionId)
                : or(isNull(milestoneFeedback.prdVersionId), eq(milestoneFeedback.prdVersionId, ''))
            )
          )
          .limit(1)
        return !!existing
      },
      createFeedback: async (
        ownerUserId: string,
        requestBody
      ) => {
        const feedbackInsert: MilestoneFeedbackInsert = {
          userId: ownerUserId,
          projectId: requestBody.projectId,
          prdVersionId: requestBody.prdVersionId ?? null,
          milestoneType: requestBody.milestoneType,
          ratingType: requestBody.ratingType ?? 'stars',
          ratingValue: requestBody.ratingValue ?? null,
          comment: requestBody.comment ?? null,
        }
        const [feedback] = await db.insert(milestoneFeedback).values(feedbackInsert).returning()
        const dto = MilestoneFeedbackRowDTOSchema.safeParse(feedback)
        if (!dto.success) {
          console.error('Feedback row DTO validation failed:', dto.error.flatten())
          return err(new ExternalServiceError('db', 'Internal validation error', 500))
        }
        return ok(dto.data)
      },
    })

    const result = await useCase.execute({ userId, request: parsed.data })
    if (result.isErr()) {
      return NextResponse.json({ error: result.error.message }, { status: result.error.statusCode })
    }

    if (result.value.kind === 'duplicate') {
      const duplicate = MilestoneFeedbackDuplicateResponseSchema.safeParse({
        message: result.value.message,
      })
      return NextResponse.json(
        duplicate.success ? duplicate.data : { message: result.value.message },
        { status: 200 }
      )
    }

    return NextResponse.json(result.value.row, { status: 201 })
  } catch (error: unknown) {
    console.error('Feedback POST error:', error)
    return NextResponse.json({ error: 'Failed to save feedback' }, { status: 500 })
  }
}

export async function GET() {
  try {
    const userResult = await requireUser(headers())
    if (userResult.isErr()) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    const userId = userResult.unwrap().id

    const rows = await db
      .select()
      .from(milestoneFeedback)
      .where(eq(milestoneFeedback.userId, userId))
      .orderBy(desc(milestoneFeedback.createdAt))

    const dtoList: unknown[] = []
    for (const row of rows) {
      const v = MilestoneFeedbackRowDTOSchema.safeParse(row)
      if (v.success) dtoList.push(v.data)
    }
    const listSchema = MilestoneFeedbackRowDTOSchema.array()
    const validated = listSchema.safeParse(dtoList)
    if (!validated.success) {
      console.error('Feedback GET list validation failed:', validated.error.flatten())
      return NextResponse.json({ error: 'Internal validation error' }, { status: 500 })
    }
    return NextResponse.json(validated.data)
  } catch (error: unknown) {
    console.error('Feedback GET error:', error)
    return NextResponse.json({ error: 'Failed to fetch feedback' }, { status: 500 })
  }
}

export const dynamic = 'force-dynamic'

import { NextResponse } from 'next/server'
import { headers } from 'next/headers'
import { requireUser } from '@repo/auth/guards'
import { PrismaProjectRepository } from '@infrastructure/persistence/project-repository'
import { PrismaAdrRepository } from '@infrastructure/persistence/adr-repository'
import { GetAdrUseCase } from '@application/adr/get-adr-usecase'
import { UpdateAdrUseCase } from '@application/adr/update-adr-usecase'
import { toNextErrorResponse } from '@shared/http'

export async function GET(
  req: Request,
  { params }: { params: { id: string; number: string } }
) {
  const userResult = await requireUser(await headers())
  if (userResult.isErr()) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
  const userId = userResult.unwrap().id

  const adrNumber = parseInt(params.number, 10)
  const projectRepo = new PrismaProjectRepository()
  const adrRepo = new PrismaAdrRepository()
  const useCase = new GetAdrUseCase(projectRepo, adrRepo)
  const result = await useCase.execute(params.id, userId, adrNumber)

  if (result.isErr()) {
    return toNextErrorResponse(result.error)
  }
  return NextResponse.json(result.unwrap())
}

export async function PATCH(
  req: Request,
  { params }: { params: { id: string; number: string } }
) {
  const userResult = await requireUser(await headers())
  if (userResult.isErr()) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
  const userId = userResult.unwrap().id

  const body = await req.json()
  const adrNumber = parseInt(params.number, 10)
  const projectRepo = new PrismaProjectRepository()
  const adrRepo = new PrismaAdrRepository()
  const useCase = new UpdateAdrUseCase(projectRepo, adrRepo)
  const result = await useCase.execute({
    projectId: params.id,
    userId,
    adrNumber,
    title: body.title,
    content: body.content,
    status: body.status,
  })

  if (result.isErr()) {
    return toNextErrorResponse(result.error)
  }
  return NextResponse.json(result.unwrap())
}

