import type { CreditTransactionDTO } from '@repo/contracts/credits/credits-contracts'
import { CREDITS_UPDATED_EVENT } from '@/lib/credits-events'

interface CreditPack {
  id: string
  size: number
  priceEur: number
  label: string
  description: string
}

type CreditTransactionClient = Omit<CreditTransactionDTO, 'createdAt'> & {
  createdAt?: string
  balanceAfter?: number
}

export default function CreditsPage() {
  const router = useRouter()
  const searchParams = useSearchParams()
  const [balance, setBalance] = useState<number | null>(null)
  const [graceUsed, setGraceUsed] = useState(false)
  const [transactions, setTransactions] = useState<CreditTransactionClient[]>([])
  const [packs, setPacks] = useState<CreditPack[]>([])
  const [costs, setCosts] = useState<Record<string, number>>({})
  const [purchasing, setPurchasing] = useState<string | null>(null)
  const [loading, setLoading] = useState(true)

  const refreshCredits = useCallback(async (): Promise<void> => {
    const credRes = await fetch('/api/credits', { cache: 'no-store' })
    if (!credRes.ok) return

    const data = await credRes.json()
    setBalance(data?.creditBalance ?? 0)
    setGraceUsed(data?.graceUsed ?? false)
    setTransactions(data?.recentTransactions ?? [])
    window.dispatchEvent(new Event(CREDITS_UPDATED_EVENT))
  }, [])

  useEffect(() => {
    let cancelled = false

    const loadPage = async () => {
      setLoading(true)
      const success = searchParams?.get('success')
      const sessionId = searchParams?.get('session_id')
      const canceled = searchParams?.get('canceled') === 'true'

      try {
        if (canceled) {
          toast.error('Paiement annulé')
          router.replace('/dashboard/credits')
        }

        if (success === 'true' && sessionId) {
          const verifyRes = await fetch('/api/stripe/verify', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ sessionId }),
            cache: 'no-store',
          })

          if (verifyRes.ok) {
            const verifyData = await verifyRes.json()
            if (!verifyData?.alreadyProcessed) {
              toast.success(`${verifyData?.creditsAdded ?? 0} crédits ajoutés à votre compte !`)
            }
          } else {
            const errBody = await verifyRes.json().catch(() => ({}))
            toast.error(
              typeof errBody?.error === 'string' ? errBody.error : 'Échec de la vérification du paiement'
            )
          }

          router.replace('/dashboard/credits')
        }

        const packRes = await fetch('/api/credits/packs', { cache: 'no-store' })
        if (!cancelled) {
          if (packRes.ok) {
            const packData = await packRes.json()
            setPacks(packData?.packs ?? [])
            setCosts(packData?.costs ?? {})
          } else {
            toast.error('Impossible de charger les packs de crédits')
          }
        }

        if (!cancelled) {
          await refreshCredits()
        }
      } catch {
        if (!cancelled) toast.error('Impossible de charger les crédits')
      } finally {
        if (!cancelled) setLoading(false)
      }
    }

    void loadPage()

    return () => {
      cancelled = true
    }
  }, [searchParams, router, refreshCredits])

  const handlePurchase = async (packId: string) => {
    setPurchasing(packId)
    try {
      const res = await fetch('/api/stripe/checkout', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ packId }),
      })
      const data = await res.json()
      if (res.ok && data?.url) {
        window.location.href = data.url
      } else if (res.status === 503) {
        toast.error('Paiement indisponible : Stripe n’est pas configuré (STRIPE_SECRET_KEY).')
      } else {
        toast.error(data?.error ?? 'Échec du démarrage du paiement')
      }
    } catch {
      toast.error('Failed to start checkout')
    } finally {
      setPurchasing(null)
    }
  }

  const getTransactionIcon = (type: string) => {
    switch (type) {
      case 'grant': return <Gift className="h-4 w-4 text-green-500" />
      case 'purchase': return <ArrowUpRight className="h-4 w-4 text-blue-500" />
      case 'consumption': return <ArrowDownRight className="h-4 w-4 text-orange-500" />
      case 'auto_reload': return <Zap className="h-4 w-4 text-purple-500" />
      default: return <Coins className="h-4 w-4" />
    }
  }

  const signedAmount = (tx: CreditTransactionClient): number => {
    const amount = tx.amount ?? 0
    return tx.type === 'consumption' ? -Math.abs(amount) : Math.abs(amount)
  }

  return (
    <div className="max-w-5xl mx-auto space-y-8">
      <FadeIn>
        <div>
          <h1 className="font-display text-2xl font-bold tracking-tight">Credits</h1>
          <p className="text-sm text-muted-foreground mt-1">
            Credits power AI operations. Each operation has a defined cost.
          </p>
        </div>
      </FadeIn>

      {/* Balance Card */}
      <FadeIn delay={0.1}>
        <Card>
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Current Balance</p>
                <p className="text-4xl font-bold font-mono mt-1">{balance !== null ? balance : '...'}</p>
                {(balance ?? 0) < 0 && (
                  <div className="flex items-center gap-1.5 mt-2 text-amber-600">
                    <AlertTriangle className="h-4 w-4" />
                    <span className="text-sm">Negative balance — add credits to continue</span>
                  </div>
                )}
                {graceUsed && (balance ?? 0) <= 0 && (
                  <p className="text-xs text-muted-foreground mt-1">
                    Grace period used. Credits required for all operations.
                  </p>
                )}
              </div>
              <div className="h-16 w-16 rounded-full bg-amber-50 flex items-center justify-center">
                <Coins className="h-8 w-8 text-amber-500" />
              </div>
            </div>
          </CardContent>
        </Card>
      </FadeIn>

      {/* Credit Packs */}
      <FadeIn delay={0.15}>
        <div className="space-y-4">
          <h2 className="font-display text-lg font-semibold">Add Credits</h2>
          {loading ? (
            <Card>
              <CardContent className="py-8 text-center text-muted-foreground">
                Chargement des packs…
              </CardContent>
            </Card>
          ) : (packs?.length ?? 0) === 0 ? (
            <Card>
              <CardContent className="py-8 text-center text-muted-foreground">
                Aucun pack disponible. Réessaie dans un instant.
              </CardContent>
            </Card>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
              {(packs ?? []).map((pack: CreditPack) => (
                <Card key={pack.id} className="relative hover:shadow-md transition-shadow">
                  {pack.id === 'pack_200' && (
                    <Badge className="absolute -top-2.5 right-4 bg-primary">Popular</Badge>
                  )}
                  <CardHeader className="pb-3">
                    <CardTitle className="font-display text-lg">{pack.label}</CardTitle>
                    <CardDescription>{pack.description}</CardDescription>
                  </CardHeader>
                  <CardContent className="space-y-4">
                    <div>
                      <span className="text-3xl font-bold">€{pack.priceEur}</span>
                      <span className="text-muted-foreground ml-1">for {pack.size} credits</span>
                    </div>
                    <Button
                      className="w-full"
                      variant={pack.id === 'pack_200' ? 'default' : 'outline'}
                      onClick={() => handlePurchase(pack.id)}
                      loading={purchasing === pack.id}
                      disabled={!!purchasing}
                    >
                      <CreditCard className="mr-2 h-4 w-4" />
                      Buy {pack.size} Credits
                    </Button>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </div>
      </FadeIn>

      {/* Cost Reference */}
      <FadeIn delay={0.2}>
        <Card>
          <CardHeader>
            <CardTitle className="font-display text-base">Credit Costs per Operation</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              {[
                { label: 'Lightweight clarification', cost: costs?.clarification ?? 1 },
                { label: 'Standard decision', cost: costs?.decision ?? 3 },
                { label: 'Dynamic mini-form decision', cost: costs?.mini_form ?? 5 },
                { label: 'PRD generation / major update', cost: costs?.prd_generation ?? 10 },
                { label: 'PRD challenge / convergence', cost: costs?.prd_challenge ?? 15 },
              ].map((item: { label: string; cost: number }) => (
                <div key={item.label} className="flex items-center justify-between py-2 px-3 rounded-lg bg-muted/50">
                  <span className="text-sm">{item.label}</span>
                  <Badge variant="secondary" className="font-mono">{item.cost}</Badge>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      </FadeIn>

      {/* Transaction History */}
      <div className="space-y-4">
        <h2 className="font-display text-lg font-semibold">Transaction History</h2>
        {(transactions?.length ?? 0) === 0 ? (
          <Card>
            <CardContent className="py-8 text-center text-muted-foreground">
              No transactions yet
            </CardContent>
          </Card>
        ) : (
          <Card>
            <CardContent className="p-0">
              <div className="divide-y">
                {(transactions ?? []).map((tx) => {
                  const amt = signedAmount(tx)
                  const isPositive = amt > 0
                  return (
                  <div key={tx?.id} className="flex items-center justify-between px-4 py-3">
                    <div className="flex items-center gap-3">
                      {getTransactionIcon(tx?.type)}
                      <div>
                        <p className="text-sm font-medium capitalize">
                          {tx?.type === 'consumption' ? (tx?.operationType ?? 'usage') : tx?.type}
                        </p>
                        <p className="text-xs text-muted-foreground">
                          {tx?.createdAt ? new Date(tx.createdAt).toLocaleDateString() : ''}
                        </p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className={`text-sm font-mono font-medium ${
                        isPositive ? 'text-green-600' : 'text-orange-600'
                      }`}>
                        {isPositive ? '+' : ''}{amt}
                      </p>
                      <p className="text-xs text-muted-foreground font-mono">
                        bal: {tx?.balanceAfter ?? 0}
                      </p>
                    </div>
                  </div>
                  )
                })}
              </div>
            </CardContent>
          </Card>
        )}
      </div>
    </div>
  )
}

import { redirect } from 'next/navigation'
import { headers } from 'next/headers'
import { requireSession } from '@repo/auth/guards'
import { DashboardShell } from './_components/dashboard-shell'

export default async function DashboardLayout({
  children,
}: {
  children: React.ReactNode
}) {
  const sessionResult = await requireSession(await headers())
  if (sessionResult.isErr()) redirect('/sign-in')

  return <DashboardShell>{children}</DashboardShell>
}

'use client'

import { useState, useEffect } from 'react'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Lock, ArrowRight, CheckCircle, AlertCircle, MessageSquare } from 'lucide-react'
import { toast } from 'sonner'

interface ArchitecturePanelProps {
  projectId: string
  phase: string
  activePrdVersionId: string | null
  onOpenRefinement?: (payload: { label: string; prdVersionId: string | null }) => void
}

const ADR_SLOTS = [
  { number: 0, title: 'Architecture Style', description: 'Monolith vs modular vs microservices' },
  { number: 1, title: 'Monorepo Boundaries', description: 'Apps vs packages organization' },
  { number: 2, title: 'API Contracts', description: 'REST, tRPC, GraphQL choice' },
  { number: 3, title: 'Authentication', description: 'Auth provider and session model' },
  { number: 4, title: 'Database', description: 'ORM, migrations, schema ownership' },
  { number: 5, title: 'Testing Strategy', description: 'Test pyramid and CI gates' },
  { number: 6, title: 'Deployment', description: 'Hosting, envs, preview apps' },
  { number: 7, title: 'Observability', description: 'Logs, metrics, traces, errors' },
  { number: 8, title: 'Analytics', description: 'Event taxonomy and provider' },
  { number: 9, title: 'Logging/Monitoring', description: 'Structure, alerts, telemetry' },
  { number: 10, title: 'Wrapping Policy', description: 'No direct SDK calls; vendor-client packages' },
  { number: 11, title: 'Feature Flags', description: 'Config location and runtime eval' },
  { number: 12, title: 'Lifecycle/Marketing', description: 'Signup, activation, churn emails' },
  { number: 13, title: 'Legal/GDPR', description: 'Cookies, privacy, data export, retention' },
]

export function ArchitecturePanel({
  projectId,
  phase,
  activePrdVersionId,
  onOpenRefinement,
}: ArchitecturePanelProps) {
  const [adrs, setAdrs] = useState<any[]>([])
  const [isLocked, setIsLocked] = useState(phase === 'intake')
  const [unlocking, setUnlocking] = useState(false)
  const [checking, setChecking] = useState(false)
  const [score, setScore] = useState<any>(null)

  useEffect(() => {
    setIsLocked(phase === 'intake')
  }, [phase])

  useEffect(() => {
    const fetchAdrs = async () => {
      try {
        const res = await fetch(`/api/projects/${projectId}/adrs`)
        if (res.ok) setAdrs(await res.json())
      } catch {}
    }
    const fetchScore = async () => {
      try {
        const res = await fetch(`/api/projects/${projectId}/readiness-score`)
        if (res.ok) setScore(await res.json())
      } catch {}
    }
    fetchAdrs()
    fetchScore()
  }, [projectId])

  const handleCheckStability = async () => {
    setChecking(true)
    try {
      const res = await fetch(`/api/projects/${projectId}/phase/check`, { method: 'POST' })
      const data = await res.json()
      if (res.ok) {
        toast.success(data.message)
      } else {
        toast.error(data.message || 'PRD is not yet stable')
      }
    } catch (err) {
      toast.error('Failed to check stability')
    } finally {
      setChecking(false)
    }
  }

  const handleUnlock = async () => {
    setUnlocking(true)
    try {
      const res = await fetch(`/api/projects/${projectId}/phase/unlock`, { method: 'POST' })
      if (res.ok) {
        const data = await res.json()
        toast.success('Architecture phase unlocked!')
        setIsLocked(false)
      } else {
        const data = await res.json()
        toast.error(data.error || 'Failed to unlock')
      }
    } catch (err) {
      toast.error('Failed to unlock architecture phase')
    } finally {
      setUnlocking(false)
    }
  }

  if (isLocked) {
    return (
      <div className="space-y-6">
        <Card className="border-yellow-200 bg-yellow-50">
          <CardHeader>
            <div className="flex items-center gap-3">
              <Lock className="h-5 w-5 text-yellow-600" />
              <div>
                <CardTitle>Architecture Phase Locked</CardTitle>
                <CardDescription>Complete your PRD clarification first</CardDescription>
              </div>
            </div>
          </CardHeader>
          <CardContent className="space-y-4">
            <p className="text-sm text-gray-700">
              The Architecture phase becomes available after you've clarified and stabilized your product definition. This ensures all decisions are made with full context.
            </p>
            <div className="flex gap-2">
              <Button onClick={handleCheckStability} disabled={checking} variant="outline" size="sm">
                Check PRD Stability
              </Button>
              {!checking && (
                <Button onClick={handleUnlock} disabled={unlocking} size="sm">
                  Unlock Architecture <ArrowRight className="ml-2 h-4 w-4" />
                </Button>
              )}
            </div>
          </CardContent>
        </Card>
      </div>
    )
  }

  const totalAdrs = ADR_SLOTS.length
  const completeAdrs = adrs.filter((a) => a.status === 'complete').length

  return (
    <div className="space-y-6">
      {score && (
        <Card>
          <CardHeader>
            <CardTitle>Readiness Score (Preview)</CardTitle>
            <CardDescription>Progress towards production-grade architecture</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="rounded-lg bg-blue-50 p-4">
                <div className="text-sm font-medium text-blue-900">Clarification Coverage</div>
                <div className="text-2xl font-bold text-blue-600">{score.score}%</div>
                <div className="text-xs text-blue-700">{score.answered} question{score.answered !== 1 ? 's' : ''} answered</div>
              </div>
              <div className="rounded-lg bg-purple-50 p-4">
                <div className="text-sm font-medium text-purple-900">PRD Sections</div>
                <div className="text-2xl font-bold text-purple-600">{score.coveredSections?.length ?? 0}/8</div>
                <div className="text-xs text-purple-700">{score.remaining} section{score.remaining !== 1 ? 's' : ''} remaining</div>
              </div>
            </div>
            <p className="text-xs text-gray-600">
              Full readiness score (100 points) coming soon with more categories.
            </p>
          </CardContent>
        </Card>
      )}

      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle>Architectural Decisions</CardTitle>
              <CardDescription>
                {completeAdrs} of {totalAdrs} ADRs complete
              </CardDescription>
            </div>
            <Badge variant="default">
              {Math.round((completeAdrs / totalAdrs) * 100)}%
            </Badge>
          </div>
        </CardHeader>
        <CardContent>
          <div className="space-y-3">
            {ADR_SLOTS.map((slot) => {
              const adr = adrs.find((a) => a.adrNumber === slot.number)
              const isComplete = adr?.status === 'complete'
              const adrLabel = `ADR-${slot.number.toString().padStart(2, '0')}`
              return (
                <div
                  key={slot.number}
                  className="flex items-center justify-between gap-2 rounded-lg border p-3 hover:bg-gray-50"
                >
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                      {isComplete ? (
                        <CheckCircle className="h-4 w-4 text-green-600 flex-shrink-0" />
                      ) : (
                        <AlertCircle className="h-4 w-4 text-gray-400 flex-shrink-0" />
                      )}
                      <div>
                        <div className="font-medium text-sm">{`${adrLabel}: ${slot.title}`}</div>
                        <div className="text-xs text-gray-600">{slot.description}</div>
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-2 shrink-0">
                    {onOpenRefinement ? (
                      <Button
                        type="button"
                        variant="ghost"
                        size="icon"
                        className="h-11 w-11 sm:h-8 sm:w-8 text-muted-foreground"
                        aria-label={`Refine ${slot.title}`}
                        onClick={() =>
                          onOpenRefinement({
                            label: `ADR-${slot.number.toString().padStart(2, '0')}: ${slot.title}`,
                            prdVersionId: activePrdVersionId,
                          })
                        }
                      >
                        <MessageSquare className="h-4 w-4" />
                      </Button>
                    ) : null}
                    <Badge variant={isComplete ? 'default' : 'outline'}>
                      {isComplete ? 'Complete' : 'Draft'}
                    </Badge>
                  </div>
                </div>
              )
            })}
          </div>
        </CardContent>
      </Card>

      <div className="rounded-lg border border-blue-200 bg-blue-50 p-4">
        <div className="text-sm font-medium text-blue-900">Coming Soon</div>
        <div className="text-xs text-blue-800">
          ADR authoring UI, AI-guided generation, feature areas, scope slicing, contracts, and repo export are coming in L3+
        </div>
      </div>
    </div>
  )
}

/** @vitest-environment happy-dom */

import { createElement } from 'react'
import { createRoot, type Root } from 'react-dom/client'
import { act } from 'react-dom/test-utils'
import { describe, it, expect, vi, beforeEach, afterEach, beforeAll } from 'vitest'
import { ClarificationChat } from './clarification-chat'

vi.mock('sonner', () => ({ toast: { error: vi.fn(), success: vi.fn() } }))
vi.mock('@/components/milestone-feedback-modal', () => ({
  MilestoneFeedbackModal: () => null,
}))
vi.mock('./decision-card', () => ({
  DecisionCard: () => null,
}))

beforeAll(() => {
  globalThis.IS_REACT_ACT_ENVIRONMENT = true
})

describe('ClarificationChat — Coming up chips', () => {
  let container: HTMLDivElement
  let root: Root

  beforeEach(() => {
    container = document.createElement('div')
    document.body.appendChild(container)
    root = createRoot(container)
  })

  afterEach(() => {
    act(() => {
      root.unmount()
    })
    container.remove()
    vi.unstubAllGlobals()
    vi.restoreAllMocks()
  })

  it('shows next canonical sections based on assistant prd_section_affected from loaded history', async () => {
    const fetchMock = vi.fn(async (input: RequestInfo | URL, init?: RequestInit): Promise<Response> => {
      const url = String(input)
      if (url.endsWith('/api/projects/proj-1/questions')) {
        return new Response(
          JSON.stringify([
            {
              structuredQuestion: 'What is the vision?',
              prdImpact: 'Product Vision',
              founderAnswer: 'Build a planner',
              availableOptions: null,
              aiInterpretation: null,
            },
          ]),
          { status: 200, headers: { 'Content-Type': 'application/json' } }
        )
      }
      return new Response(JSON.stringify({}), { status: 404 })
    })

    vi.stubGlobal('fetch', fetchMock)

    await act(async () => {
      root.render(
        createElement(ClarificationChat, {
          projectId: 'proj-1',
          prdVersionId: null,
          onPrdGenerated: () => {},
        })
      )
    })

    await act(async () => {
      await new Promise((r) => setTimeout(r, 0))
    })

    expect(document.body.textContent).toContain('Coming up')
    expect(document.body.textContent).toContain('Target Users')
    expect(document.body.textContent).toContain('Core Features')
    expect(document.body.textContent).toContain('User Journeys')
  })
})

'use client'

import { useState, useRef, useEffect, useCallback, useMemo } from 'react'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Textarea } from '@/components/ui/textarea'
import { Badge } from '@/components/ui/badge'
import { ScrollArea } from '@/components/ui/scroll-area'
import {
  Send, Sparkles, FileText, AlertTriangle, Loader2, RefreshCw,
  HelpCircle, Check, X,
} from 'lucide-react'
import {
  ChatMessageToolbar,
  copyTextToClipboard,
  toastCopied,
  toastCopyFailed,
} from './chat-message-toolbar'
import { messagesToClientThread } from './clarify-thread-utils'
import { DecisionCard } from './decision-card'
import { toast } from 'sonner'
import { MilestoneFeedbackModal } from '@/components/milestone-feedback-modal'
import {
  ClarifyDecisionUiSchema,
  type ClarifyDecisionUi,
} from '@repo/contracts/ai/decision-ui'
import { comingUpPrdSectionsFromAssistantParsed } from '@repo/contracts/questions/history'
import { useOwnerMilestonePrompt } from './owner-milestone-prompt'

interface Message {
  id: string
  role: 'user' | 'assistant' | 'system'
  content: string
  parsed?: Record<string, unknown>
  decisionResponse?: Record<string, unknown>
}

function newMsgId(): string {
  return crypto.randomUUID()
}

interface ClarificationChatProps {
  projectId: string
  prdVersionId: string | null
  onPrdGenerated: () => void
}

export function ClarificationChat({ projectId, prdVersionId, onPrdGenerated }: ClarificationChatProps) {
  const { notifyMilestone } = useOwnerMilestonePrompt()
  const [messages, setMessages] = useState<Message[]>([])
  const [input, setInput] = useState('')
  const [streaming, setStreaming] = useState(false)
  const [generatingPrd, setGeneratingPrd] = useState(false)
  const [showFeedback, setShowFeedback] = useState(false)
  const [feedbackMilestone, setFeedbackMilestone] = useState('')
  const [editingId, setEditingId] = useState<string | null>(null)
  const [editDraft, setEditDraft] = useState('')
  const scrollRef = useRef<HTMLDivElement>(null)
  const hasStarted = useRef(false)
  /** Thread used for the in-flight clarify request (avoids stale append after truncate). */
  const activeThreadRef = useRef<Message[]>([])

  const scrollToBottom = useCallback(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight
    }
  }, [])

  const comingUpSections = useMemo(() => {
    const sections = (messages ?? [])
      .filter((m) => m.role === 'assistant')
      .map((m) => m.parsed?.prd_section_affected as string | undefined)
    return comingUpPrdSectionsFromAssistantParsed(sections, 3)
  }, [messages])

  const showReadyToGenerateHint =
    comingUpSections.length === 0 && (messages ?? []).some((m) => m.role === 'assistant')

  useEffect(() => { scrollToBottom() }, [messages, scrollToBottom])

  // Load existing history on mount; auto-start only when there are no prior messages.
  useEffect(() => {
    if (hasStarted.current) return
    hasStarted.current = true

    const loadHistory = async () => {
      try {
        const res = await fetch(`/api/projects/${projectId}/questions`)
        if (res.ok) {
          const data = await res.json()
          if (Array.isArray(data) && data.length > 0) {
            const historic: Message[] = []
            for (const q of data) {
              const parsed: Record<string, unknown> = { message: q.structuredQuestion }
              if (q.availableOptions) parsed.decision_ui = q.availableOptions
              if (q.aiInterpretation) parsed.reasoning = q.aiInterpretation
              if (q.prdImpact) parsed.prd_section_affected = q.prdImpact
              historic.push({
                id: newMsgId(),
                role: 'assistant',
                content: q.structuredQuestion,
                parsed,
              })
              if (q.founderAnswer) {
                historic.push({ id: newMsgId(), role: 'user', content: q.founderAnswer })
              }
            }
            setMessages(historic)
            return
          }
        }
      } catch {
        // Fall through to auto-start on error
      }
      // No history (or fetch failed) — start a fresh clarification session
      sendMessage(null, null)
    }

    loadHistory()
  }, [projectId])

  const sendMessage = async (
    userMessage: string | null,
    decisionResponse: Record<string, unknown> | null,
    options?: { threadBase?: Message[]; skipAppendUser?: boolean }
  ) => {
    if (streaming) return

    let thread = options?.threadBase ?? messages

    if (!options?.skipAppendUser && (userMessage || decisionResponse)) {
      const displayContent = decisionResponse
        ? `Selected: ${JSON.stringify(decisionResponse?.selected ?? decisionResponse)}`
        : userMessage ?? ''
      const userMsg: Message = {
        id: newMsgId(),
        role: 'user',
        content: displayContent,
        ...(decisionResponse ? { decisionResponse } : {}),
      }
      thread = [...thread, userMsg]
    }

    activeThreadRef.current = thread
    setMessages(thread)

    setStreaming(true)
    setInput('')
    setEditingId(null)

    try {
      const res = await fetch(`/api/projects/${projectId}/clarify`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          message: userMessage,
          decisionResponse,
          prdVersionId,
          clientThread: messagesToClientThread(thread),
        }),
      })

      if (res?.status === 402) {
        const data = await res.json()
        toast.error(data?.message ?? 'Insufficient credits')
        setStreaming(false)
        return
      }

      if (!res?.ok) {
        throw new Error('Failed to get AI response')
      }

      // Stream response
      const reader = res.body?.getReader()
      const decoder = new TextDecoder()
      let partialRead = ''
      let assistantContent = ''
      let streamCompleted = false

      const appendAssistantFromBuffer = (raw: string) => {
        let parsedResult: Record<string, unknown>
        try {
          parsedResult = JSON.parse(raw) as Record<string, unknown>
        } catch {
          parsedResult = { message: raw }
        }
        const messageText =
          typeof parsedResult.message === 'string' ? parsedResult.message : raw

        const assistantMsg: Message = {
          id: newMsgId(),
          role: 'assistant',
          content: messageText,
          parsed: parsedResult,
        }
        const nextThread = [...activeThreadRef.current, assistantMsg]
        activeThreadRef.current = nextThread
        setMessages(nextThread)
      }

      const handleSseLine = (line: string) => {
        if (!line.startsWith('data: ')) return
        const data = line.slice(6)
        try {
          const parsed = JSON.parse(data) as {
            status?: string
            partial?: string
            result?: string
            message?: string
          }
          if (parsed?.status === 'processing') {
            assistantContent += parsed?.partial ?? ''
          } else if (parsed?.status === 'completed') {
            streamCompleted = true
            assistantContent = parsed?.result ?? assistantContent
            appendAssistantFromBuffer(assistantContent)
          } else if (parsed?.status === 'error') {
            toast.error(parsed?.message ?? 'AI error')
          }
        } catch {
          /* ignore malformed chunk */
        }
      }

      while (reader) {
        const { done, value } = await reader.read()
        if (done) break

        partialRead += decoder.decode(value, { stream: true })
        const lines = partialRead.split('\n')
        partialRead = lines.pop() ?? ''

        for (const line of lines) {
          handleSseLine(line)
        }
      }

      if (partialRead.trim()) {
        handleSseLine(partialRead.trim())
      }

      if (!streamCompleted && assistantContent.trim()) {
        appendAssistantFromBuffer(assistantContent)
      }
    } catch (error: any) {
      console.error('Clarification error:', error)
      toast.error('Failed to get AI response')
    } finally {
      setStreaming(false)
    }
  }

  const handleSend = () => {
    const msg = input.trim()
    if (!msg) return
    sendMessage(msg, null)
  }

  const handleDecision = (response: Record<string, unknown>) => {
    void sendMessage(null, response)
  }

  const handleCopy = async (text: string) => {
    const ok = await copyTextToClipboard(text)
    if (ok) toastCopied()
    else toastCopyFailed()
  }

  const startEdit = (msg: Message) => {
    if (streaming || msg.decisionResponse) return
    setEditingId(msg.id)
    setEditDraft(msg.content)
  }

  const submitEdit = async (messageId: string) => {
    const text = editDraft.trim()
    if (!text || streaming) return
    const index = messages.findIndex((m) => m.id === messageId)
    if (index < 0 || messages[index]?.role !== 'user') return
    const thread = [
      ...messages.slice(0, index),
      { ...messages[index], content: text },
    ]
    activeThreadRef.current = thread
    setMessages(thread)
    setEditingId(null)
    setEditDraft('')
    await sendMessage(text, null, { threadBase: thread, skipAppendUser: true })
  }

  const resendFromUserMessage = async (userMessageId: string) => {
    if (streaming) return
    const userIndex = messages.findIndex((m) => m.id === userMessageId && m.role === 'user')
    if (userIndex < 0) return
    const userMsg = messages[userIndex]
    const thread = messages.slice(0, userIndex + 1)
    activeThreadRef.current = thread
    setMessages(thread)
    setEditingId(null)
    setEditDraft('')
    const prompt = userMsg.decisionResponse ? null : userMsg.content
    await sendMessage(prompt, userMsg.decisionResponse ?? null, {
      threadBase: thread,
      skipAppendUser: true,
    })
  }

  const regenerateAssistant = async (assistantId: string) => {
    if (streaming) return
    const aiIndex = messages.findIndex((m) => m.id === assistantId && m.role === 'assistant')
    if (aiIndex < 0) return
    let userIndex = aiIndex - 1
    while (userIndex >= 0 && messages[userIndex]?.role !== 'user') userIndex -= 1
    if (userIndex < 0) return
    const userMsg = messages[userIndex]
    const thread = messages.slice(0, aiIndex)
    activeThreadRef.current = thread
    setMessages(thread)
    setEditingId(null)
    const prompt = userMsg.decisionResponse ? null : userMsg.content
    await sendMessage(prompt, userMsg.decisionResponse ?? null, {
      threadBase: thread,
      skipAppendUser: true,
    })
  }

  const handleGeneratePrd = async () => {
    setGeneratingPrd(true)
    try {
      const res = await fetch(`/api/projects/${projectId}/generate-prd`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({}),
      })

      if (res?.status === 402) {
        const data = await res.json()
        toast.error(data?.message ?? 'Insufficient credits')
        setGeneratingPrd(false)
        return
      }

      if (!res?.ok) throw new Error('Failed to generate PRD')

      // Stream through but we mainly care about completion
      const reader = res.body?.getReader()
      const decoder = new TextDecoder()
      let partialRead = ''

      while (reader) {
        const { done, value } = await reader.read()
        if (done) break
        partialRead += decoder.decode(value, { stream: true })
        const lines = partialRead.split('\n')
        partialRead = lines.pop() ?? ''

        for (const line of lines) {
          if (line.startsWith('data: ')) {
            try {
              const parsed = JSON.parse(line.slice(6))
              if (parsed?.status === 'completed') {
                toast.success('PRD generated!')
                onPrdGenerated()
                // Trigger milestone feedback
                setFeedbackMilestone('prd_created')
                setShowFeedback(true)
                notifyMilestone({
                  projectId,
                  milestoneType: 'prd_created',
                  ...(prdVersionId ? { prdVersionId } : {}),
                })
              }
            } catch { }
          }
        }
      }
    } catch (error: any) {
      console.error('PRD generation error:', error)
      toast.error('Failed to generate PRD')
    } finally {
      setGeneratingPrd(false)
    }
  }

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      handleSend()
    }
  }

  return (
    <div className="flex flex-col h-[calc(100vh-240px)] min-h-[500px]">
      {/* Messages */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto space-y-4 pb-4 pr-1">
        {(messages ?? []).length === 0 && !streaming && (
          <div className="flex flex-col items-center justify-center h-full text-center">
            <Sparkles className="h-10 w-10 text-primary/30 mb-3" />
            <p className="text-muted-foreground">Starting clarification...</p>
          </div>
        )}

        {(messages ?? []).map((msg: Message, i: number) => (
          <div key={msg.id} className={`group flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            {msg.role === 'user' ? (
              <div className="max-w-[85%] min-w-0 w-full flex justify-end flex-col">
                <div className="flex items-start gap-1 min-w-0 w-full max-w-full">

                  <div className="flex-1 min-w-0">
                    {editingId === msg.id ? (
                      <div className="space-y-2">
                        <Textarea
                          value={editDraft}
                          onChange={(e) => setEditDraft(e.target.value)}
                          rows={3}
                          className="resize-none text-sm w-full h-[200px]"
                          disabled={streaming}
                          aria-label="Modifier le message"
                        />
                        <div className="flex flex-wrap justify-end gap-1">
                          <Button type="button" size="sm" variant="ghost" onClick={() => setEditingId(null)}>
                            <X className="h-3.5 w-3.5 mr-1" />
                            Annuler
                          </Button>
                          <Button
                            type="button"
                            size="sm"
                            onClick={() => void submitEdit(msg.id)}
                            disabled={!editDraft.trim() || streaming}
                          >
                            <Check className="h-3.5 w-3.5 mr-1" />
                            Renvoyer
                          </Button>
                        </div>
                      </div>
                    ) : (
                      <div className="bg-primary text-primary-foreground rounded-2xl rounded-br-sm px-4 py-2.5 w-full">
                        <p className="text-sm whitespace-pre-wrap break-words">{msg.content}</p>
                      </div>
                    )}
                  </div>
                </div>
                {editingId !== msg.id && (
                  <ChatMessageToolbar
                    role="user"
                    disabled={streaming || !!msg.decisionResponse}
                    onCopy={() => void handleCopy(msg.content)}
                    onEdit={msg.decisionResponse ? undefined : () => startEdit(msg)}
                    onRegenerate={
                      msg.decisionResponse ? undefined : () => void resendFromUserMessage(msg.id)
                    }
                  />
                )}
              </div>
            ) : (
              <div className="max-w-[85%] space-y-3">
                {/* Reasoning chip */}
                {typeof msg.parsed?.reasoning === 'string' && msg.parsed.reasoning ? (
                  <div className="flex items-start gap-2 text-xs text-muted-foreground bg-muted/50 rounded-lg px-3 py-2">
                    <HelpCircle className="h-3.5 w-3.5 mt-0.5 flex-shrink-0" />
                    <span>{msg.parsed.reasoning}</span>
                  </div>
                ) : null}

                {/* Main message */}
                <div className="flex items-start gap-1 flex-col">
                  <Card className="flex-1 min-w-0">
                    <CardContent className="p-4">
                      <p className="text-sm whitespace-pre-wrap">{msg.content}</p>
                      {typeof msg.parsed?.progress_hint === 'string' && msg.parsed.progress_hint ? (
                        <div className="mt-3 flex items-center gap-2">
                          <button
                            type="button"
                            disabled={streaming}
                            onClick={() => void sendMessage(msg.parsed?.progress_hint as string, null)}
                            className="disabled:opacity-50"
                          >
                            <Badge variant="secondary" className="text-xs cursor-pointer">
                              {msg.parsed.progress_hint as string}
                            </Badge>
                          </button>

                          {typeof msg.parsed?.prd_section_affected === 'string' && msg.parsed.prd_section_affected ? (
                            <Badge variant="outline" className="text-xs">
                              → {msg.parsed.prd_section_affected as string}
                            </Badge>
                          ) : null}
                        </div>
                      ) : null}
                    </CardContent>
                  </Card>
                  <div className="flex items-start gap-1 self-end">
                    <ChatMessageToolbar
                      role="assistant"
                      disabled={streaming}
                      onCopy={() =>
                        void handleCopy(
                          typeof msg.parsed?.reasoning === 'string'
                            ? `${msg.content}\n\n${msg.parsed.reasoning}`
                            : msg.content
                        )
                      }
                      onRegenerate={() => void regenerateAssistant(msg.id)}
                    />
                  </div>
                </div>

                {/* Decision UI */}
                {(() => {
                  const parsedDecision = ClarifyDecisionUiSchema.safeParse(
                    msg.parsed?.decision_ui
                  )
                  if (!parsedDecision.success) return null
                  const decisionUi: ClarifyDecisionUi = parsedDecision.data
                  return (
                    <DecisionCard
                      decision={decisionUi}
                      onSubmit={handleDecision}
                      disabled={streaming || i !== (messages?.length ?? 0) - 1}
                    />
                  )
                })()}
              </div>
            )}
          </div>
        ))}

        {streaming && (
          <div className="flex justify-start">
            <div className="flex items-center gap-2 text-muted-foreground bg-muted rounded-lg px-4 py-3">
              <Loader2 className="h-4 w-4 animate-spin" />
              <span className="text-sm">Thinking...</span>
            </div>
          </div>
        )}
      </div>

      {/* Input area */}
      <div className="border-t pt-4 space-y-3">
        {comingUpSections.length > 0 && (
          <div
            className="flex flex-col gap-2 sm:flex-row sm:items-center sm:gap-3"
            aria-label="Upcoming PRD sections"
          >
            <span className="text-xs font-medium text-muted-foreground shrink-0">Coming up</span>
            <div className="flex flex-wrap gap-2">
              {comingUpSections.map((label) => (
                <Badge key={label} variant="secondary" className="text-xs font-normal max-w-full truncate">
                  {label}
                </Badge>
              ))}
            </div>
          </div>
        )}
        {showReadyToGenerateHint && (
          <p className="text-xs text-muted-foreground">
            Ready to generate PRD — every canonical section has had a question in this workspace.
          </p>
        )}
        <div className="flex gap-2">
          <Textarea
            placeholder="Type your response or add context..."
            value={input}
            onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            rows={2}
            className="resize-none flex-1"
            disabled={streaming}
          />
          <div className="flex flex-col gap-2">
            <Button
              size="icon"
              onClick={handleSend}
              disabled={!input.trim() || streaming}
            >
              <Send className="h-4 w-4" />
            </Button>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <Button
            variant="outline"
            size="sm"
            onClick={handleGeneratePrd}
            loading={generatingPrd}
            disabled={streaming || (messages?.length ?? 0) < 2}
          >
            <FileText className="mr-2 h-4 w-4" />
            Generate PRD
          </Button>
          <span className="text-xs text-muted-foreground">
            10 credits · Generates a versioned PRD from your clarifications
          </span>
        </div>
      </div>

      {/* Milestone feedback */}
      <MilestoneFeedbackModal
        open={showFeedback}
        onClose={() => setShowFeedback(false)}
        projectId={projectId}
        prdVersionId={prdVersionId}
        milestoneType={feedbackMilestone}
        title={feedbackMilestone === 'prd_created' ? 'PRD Generated!' : 'How was that?'}
        description="Your feedback helps improve the product clarification experience."
      />
    </div>
  )
}

import type { ClarifyClientThreadMessage } from '@repo/contracts/questions/history'

export type ThreadMessageLike = {
  role: 'user' | 'assistant' | 'system'
  content: string
  reasoning?: string
  parsed?: Record<string, unknown>
}

export function messagesToClientThread(
  messages: readonly ThreadMessageLike[]
): ClarifyClientThreadMessage[] {
  return messages
    .filter((m) => m.role === 'user' || m.role === 'assistant')
    .map((m) => ({
      role: m.role as 'user' | 'assistant',
      content: m.content,
      ...(m.role === 'assistant'
        ? {
            reasoning:
              m.reasoning ??
              (typeof m.parsed?.reasoning === 'string' ? m.parsed.reasoning : undefined),
          }
        : {}),
    }))
}

'use client';

import { useCallback, useEffect, useState } from 'react';
import Link from 'next/link';
import { Button } from '@/components/ui/button';
import { FadeIn } from '@/components/ui/animate';
import { toast } from 'sonner';
import {
  ArrowLeft,
  BookOpen,
  CheckCircle,
  Loader2,
  Plus,
  Trash2,
} from 'lucide-react';
import {
  FeatureSplitListResponseSchema,
  type FeatureCluster,
} from '@repo/contracts/feature-split/feature-split';
import { UserStoryCorpusSchema, type UserStoryCorpusDTO } from '@repo/contracts/user-stories';

interface ClusterStoriesDetailProps {
  projectId: string;
  projectName: string;
  clusterId: string;
}

type LineDraft = {
  id?: string;
  sortOrder: number;
  title: string;
  body: string;
  archivedAt?: string | null;
  draftMarker?: string | null;
};

function emptyLine(sortOrder: number): LineDraft {
  return { sortOrder, title: '', body: '' };
}

function corpusToDrafts(corpus: UserStoryCorpusDTO): LineDraft[] {
  const active = corpus.lines.filter((l) => !l.archivedAt);
  const sorted = [...active].sort((a, b) => a.sortOrder - b.sortOrder);
  return sorted.map((l) => ({
    id: l.id,
    sortOrder: l.sortOrder,
    title: l.title,
    body: l.body,
    draftMarker: l.draftMarker,
  }));
}

export function ClusterStoriesDetail({
  projectId,
  projectName,
  clusterId,
}: ClusterStoriesDetailProps) {
  const [cluster, setCluster] = useState<FeatureCluster | null>(null);
  const [lines, setLines] = useState<LineDraft[]>([emptyLine(0)]);
  const [reviewReadyAt, setReviewReadyAt] = useState<Date | null>(null);
  const [hasPersistedCorpus, setHasPersistedCorpus] = useState(false);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [markingReady, setMarkingReady] = useState(false);

  const fetchCluster = useCallback(async () => {
    try {
      const res = await fetch(`/api/projects/${projectId}/feature-split`);
      if (!res.ok) return;
      const raw = await res.json();
      const parsed = FeatureSplitListResponseSchema.safeParse(raw);
      if (!parsed.success) return;
      for (const split of parsed.data) {
        const found = split.clusters?.find((c) => c.id === clusterId);
        if (found) {
          setCluster(found);
          return;
        }
      }
    } catch {
      // network
    }
  }, [projectId, clusterId]);

  const fetchCorpus = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch(
        `/api/projects/${projectId}/user-stories?featureSplitClusterId=${encodeURIComponent(clusterId)}`
      );
      if (res.status === 404) {
        setLines([emptyLine(0)]);
        setReviewReadyAt(null);
        setHasPersistedCorpus(false);
        return;
      }
      if (!res.ok) {
        toast.error('Could not load stories');
        return;
      }
      const raw = await res.json();
      const parsed = UserStoryCorpusSchema.safeParse(raw);
      if (!parsed.success) {
        toast.error('Unexpected response');
        return;
      }
      const corpus = parsed.data;
      setReviewReadyAt(corpus.reviewReadyAt);
      setHasPersistedCorpus(true);
      const drafts = corpusToDrafts(corpus);
      setLines(drafts.length > 0 ? drafts : [emptyLine(0)]);
    } catch {
      toast.error('Network error');
    } finally {
      setLoading(false);
    }
  }, [projectId, clusterId]);

  useEffect(() => {
    fetchCluster();
    fetchCorpus();
  }, [fetchCluster, fetchCorpus]);

  const handleLineChange = (index: number, field: keyof LineDraft, value: string | number) => {
    setLines((prev) => prev.map((line, i) => (i === index ? { ...line, [field]: value } : line)));
  };

  const handleAddLine = () => {
    setLines((prev) => [...prev, emptyLine(prev.length)]);
  };

  const handleRemoveLine = (index: number) => {
    setLines((prev) =>
      prev
        .filter((_, i) => i !== index)
        .map((line, i) => ({ ...line, sortOrder: i }))
    );
  };

  const handleSave = async () => {
    const valid = lines.filter((l) => l.title.trim() && l.body.trim());
    if (valid.length === 0) {
      toast.error('Add at least one story with title and description');
      return;
    }
    setSaving(true);
    try {
      const res = await fetch(`/api/projects/${projectId}/user-stories`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          featureSplitClusterId: clusterId,
          lines: valid.map((l) => ({
            ...(l.id ? { id: l.id } : {}),
            sortOrder: l.sortOrder,
            title: l.title.trim(),
            body: l.body.trim(),
            archivedAt: l.archivedAt ?? null,
            draftMarker: l.draftMarker ?? null,
          })),
        }),
      });
      const raw = await res.json();
      if (!res.ok) {
        toast.error(raw?.error ?? 'Save failed');
        return;
      }
      const parsed = UserStoryCorpusSchema.safeParse(raw);
      if (parsed.success) {
        setReviewReadyAt(parsed.data.reviewReadyAt);
        setHasPersistedCorpus(true);
        const drafts = corpusToDrafts(parsed.data);
        setLines(drafts.length > 0 ? drafts : [emptyLine(0)]);
      }
      toast.success('Stories saved');
    } catch {
      toast.error('Network error while saving');
    } finally {
      setSaving(false);
    }
  };

  const handleMarkReviewReady = async () => {
    if (!hasPersistedCorpus) return;
    setMarkingReady(true);
    try {
      const res = await fetch(`/api/projects/${projectId}/user-stories/review-ready`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ featureSplitClusterId: clusterId }),
      });
      const raw = await res.json();
      if (!res.ok) {
        toast.error(raw?.error ?? 'Could not mark review-ready');
        return;
      }
      const parsed = UserStoryCorpusSchema.safeParse(raw);
      if (parsed.success) {
        setReviewReadyAt(parsed.data.reviewReadyAt);
        const drafts = corpusToDrafts(parsed.data);
        setLines(drafts.length > 0 ? drafts : [emptyLine(0)]);
      }
      toast.success('Marked ready for review');
    } catch {
      toast.error('Network error');
    } finally {
      setMarkingReady(false);
    }
  };

  return (
    <div className="min-h-screen bg-background">
      <div className="mx-auto max-w-3xl px-4 py-8 sm:px-6 lg:px-8">
        <FadeIn>
          <div className="mb-6">
            <Link
              href={`/dashboard/projects/${projectId}/user-stories`}
              className="inline-flex items-center gap-2 text-sm text-muted-foreground hover:text-foreground mb-3 min-h-[44px]"
            >
              <ArrowLeft className="h-4 w-4" />
              All clusters
            </Link>
            <div className="flex flex-col gap-1 sm:flex-row sm:items-center sm:justify-between">
              <div>
                <h1 className="text-xl sm:text-2xl font-bold tracking-tight flex items-center gap-2">
                  <BookOpen className="h-6 w-6 shrink-0 text-primary" />
                  {cluster?.label ?? 'User stories'}
                </h1>
                <p className="text-muted-foreground text-sm mt-0.5">{projectName}</p>
              </div>
              {reviewReadyAt && (
                <p className="text-sm text-emerald-600 dark:text-emerald-400 flex items-center gap-1.5 shrink-0">
                  <CheckCircle className="h-4 w-4 shrink-0" />
                  Review-ready
                </p>
              )}
            </div>
            {cluster?.valueLine && (
              <p className="mt-2 text-sm text-muted-foreground">{cluster.valueLine}</p>
            )}
          </div>

          {loading ? (
            <div className="flex justify-center py-16">
              <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
            </div>
          ) : (
            <div className="space-y-4">
              {lines.map((line, index) => (
                <div
                  key={line.id ?? `new-${index}`}
                  className="rounded-lg border bg-card p-4 sm:p-5 space-y-3"
                >
                  <div className="flex items-center justify-between gap-2">
                    <span className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
                      Story {index + 1}
                    </span>
                    <Button
                      type="button"
                      variant="ghost"
                      size="icon"
                      className="shrink-0 h-9 w-9 text-destructive hover:text-destructive"
                      onClick={() => handleRemoveLine(index)}
                      aria-label="Remove story"
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                  <input
                    className="w-full min-h-[44px] rounded-md border bg-background px-3 py-2 text-base font-medium"
                    placeholder="Title"
                    value={line.title}
                    onChange={(e) => handleLineChange(index, 'title', e.target.value)}
                  />
                  <textarea
                    className="w-full min-h-[140px] rounded-md border bg-background px-3 py-2 text-sm leading-relaxed resize-none"
                    placeholder="Given … When … Then …"
                    value={line.body}
                    onChange={(e) => handleLineChange(index, 'body', e.target.value)}
                  />
                </div>
              ))}

              <Button
                type="button"
                variant="outline"
                onClick={handleAddLine}
                className="min-h-[44px] w-full"
              >
                <Plus className="h-4 w-4 mr-2" />
                Add story
              </Button>

              <div className="flex flex-col gap-2 sm:flex-row pt-2 border-t">
                <Button
                  type="button"
                  variant="outline"
                  disabled={saving}
                  onClick={handleSave}
                  className="min-h-[44px] sm:flex-1"
                >
                  {saving ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : null}
                  Save
                </Button>
                <Button
                  type="button"
                  variant="outline"
                  disabled={markingReady || !hasPersistedCorpus}
                  onClick={handleMarkReviewReady}
                  className="min-h-[44px] sm:flex-1"
                >
                  {markingReady ? (
                    <Loader2 className="h-4 w-4 animate-spin mr-2" />
                  ) : (
                    <CheckCircle className="h-4 w-4 mr-2" />
                  )}
                  Mark review-ready
                </Button>
              </div>
            </div>
          )}
        </FadeIn>
      </div>
    </div>
  );
}

import { PRD_SECTIONS } from '@repo/contracts/questions'

/** Minimal message shape for “Coming up” preview (assistant `prd_section_affected`). */
export type ClarifyMessageForComingUp = {
  role: 'user' | 'assistant' | 'system'
  parsed?: { prd_section_affected?: unknown } | null
}

const canonical = new Set<string>(PRD_SECTIONS as unknown as string[])

/** Next canonical PRD sections not yet touched by assistant messages, in pipeline order (max `limit`). */
export function selectComingUpSections(messages: ClarifyMessageForComingUp[], limit = 3): string[] {
  const covered = new Set<string>()
  for (const m of messages) {
    if (m.role !== 'assistant') continue
    const raw = m.parsed?.prd_section_affected
    if (typeof raw !== 'string') continue
    const s = raw.trim()
    if (canonical.has(s)) covered.add(s)
  }
  return PRD_SECTIONS.filter((section) => !covered.has(section)).slice(0, limit)
}

'use client'

import { useState } from 'react'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Textarea } from '@/components/ui/textarea'
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group'
import { Checkbox } from '@/components/ui/checkbox'
import { Label } from '@/components/ui/label'
import { HelpCircle, Send, MessageSquare } from 'lucide-react'
import type {
  ClarifyDecisionUi,
  ClarifyDecisionOption,
} from '@repo/contracts/ai/decision-ui'

interface DecisionCardProps {
  decision: ClarifyDecisionUi
  onSubmit: (response: any) => void
  disabled?: boolean
}

export function DecisionCard({ decision, onSubmit, disabled = false }: DecisionCardProps) {
  const [singleChoice, setSingleChoice] = useState('')
  const [multiChoices, setMultiChoices] = useState<string[]>([])
  const [ranked, setRanked] = useState<string[]>(
    () => (decision?.options ?? []).map((o: ClarifyDecisionOption) => o.id)
  )
  const [comment, setComment] = useState('')
  const [customInput, setCustomInput] = useState('')
  const [showComment, setShowComment] = useState(false)

  const options = decision?.options ?? []
  const type = decision?.type ?? 'single_choice'

  // Simple choice: single_choice with 2-5 options, no per-option descriptions, no custom input
  const isSimpleChoice =
    type === 'single_choice' &&
    options.length >= 2 &&
    options.length <= 5 &&
    options.every((o: ClarifyDecisionOption) => !o.description) &&
    !decision?.allow_custom

  const handleSubmit = () => {
    let response: any = { type }

    switch (type) {
      case 'single_choice':
        if (!singleChoice && !customInput.trim()) return
        response.selected = singleChoice || `custom: ${customInput.trim()}`
        response.label = options.find((o: ClarifyDecisionOption) => o.id === singleChoice)?.label ?? customInput.trim()
        break
      case 'multi_choice':
        if ((multiChoices?.length ?? 0) === 0 && !customInput.trim()) return
        response.selected = multiChoices
        response.labels = multiChoices.map((id: string) => options.find((o: ClarifyDecisionOption) => o.id === id)?.label ?? id)
        if (customInput.trim()) response.custom = customInput.trim()
        break
      case 'ranked':
        response.ranking = ranked
        response.labels = ranked.map((id: string) => options.find((o: ClarifyDecisionOption) => o.id === id)?.label ?? id)
        break
      case 'modal_form':
        response.selected = singleChoice || multiChoices
        break
    }

    if (comment.trim()) response.comment = comment.trim()
    onSubmit(response)
  }

  const handleNotSure = () => {
    onSubmit({ type: 'not_sure', message: "I'm not sure about this. Can you ask differently?" })
  }

  const toggleMulti = (id: string) => {
    setMultiChoices((prev: string[]) =>
      (prev ?? []).includes(id)
        ? (prev ?? []).filter((x: string) => x !== id)
        : [...(prev ?? []), id]
    )
  }

  const moveRanked = (fromIndex: number, toIndex: number) => {
    if (toIndex < 0 || toIndex >= (ranked?.length ?? 0)) return
    const newRanked = [...(ranked ?? [])]
    const [moved] = newRanked.splice(fromIndex, 1)
    newRanked.splice(toIndex, 0, moved)
    setRanked(newRanked)
  }

  // Compact pill buttons for simple single_choice (2-5 options, no descriptions, no custom)
  if (isSimpleChoice) {
    return (
      <div className="flex flex-wrap gap-1.5 mt-1">
        {options.map((opt: ClarifyDecisionOption) => (
          <Button
            key={opt.id}
            variant="outline"
            size="sm"
            disabled={disabled}
            onClick={() => {
              if (disabled) return
              onSubmit({ type, selected: opt.id, label: opt.label })
            }}
            className="h-8 text-xs rounded-full px-3 hover:bg-primary hover:text-primary-foreground transition-colors"
          >
            {opt.label}
          </Button>
        ))}
        {decision?.allow_not_sure && (
          <Button
            variant="ghost"
            size="sm"
            onClick={handleNotSure}
            disabled={disabled}
            className="h-8 text-xs rounded-full px-3 text-muted-foreground"
          >
            Not sure
          </Button>
        )}
      </div>
    )
  }

  // Full card for complex cases (multi_choice, ranked, options with descriptions, allow_custom)
  return (
    <Card className="border-border/60 bg-muted/30">
      <CardContent className="p-3 space-y-3">
        {decision?.description && (
          <p className="text-xs text-muted-foreground">{decision.description}</p>
        )}

        {/* Single Choice */}
        {type === 'single_choice' && (
          <RadioGroup value={singleChoice} onValueChange={setSingleChoice} disabled={disabled}>
            <div className="space-y-1.5">
              {options.map((opt: ClarifyDecisionOption) => (
                <div
                  key={opt.id}
                  className="flex items-start gap-2.5 p-2 rounded-md border hover:bg-muted/50 transition-colors cursor-pointer"
                  onClick={() => !disabled && setSingleChoice(opt.id)}
                >
                  <RadioGroupItem value={opt.id} id={opt.id} className="mt-0.5 shrink-0" />
                  <div>
                    <Label htmlFor={opt.id} className="text-sm font-medium cursor-pointer leading-tight">{opt.label}</Label>
                    {opt.description && (
                      <p className="text-xs text-muted-foreground mt-0.5">{opt.description}</p>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </RadioGroup>
        )}

        {/* Multi Choice */}
        {type === 'multi_choice' && (
          <div className="space-y-1.5">
            {options.map((opt: ClarifyDecisionOption) => (
              <div
                key={opt.id}
                className="flex items-start gap-2.5 p-2 rounded-md border hover:bg-muted/50 transition-colors cursor-pointer"
                onClick={() => !disabled && toggleMulti(opt.id)}
              >
                <Checkbox
                  checked={(multiChoices ?? []).includes(opt.id)}
                  onCheckedChange={() => toggleMulti(opt.id)}
                  disabled={disabled}
                  className="mt-0.5 shrink-0"
                />
                <div>
                  <span className="text-sm font-medium">{opt.label}</span>
                  {opt.description && (
                    <p className="text-xs text-muted-foreground mt-0.5">{opt.description}</p>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Ranked */}
        {type === 'ranked' && (
          <div className="space-y-1">
            {(ranked ?? []).map((id: string, index: number) => {
              const opt = options.find((o: ClarifyDecisionOption) => o.id === id)
              return (
                <div
                  key={id}
                  className="flex items-center gap-2 p-2 rounded-md border bg-background"
                >
                  <span className="text-xs font-mono text-muted-foreground w-4 shrink-0">{index + 1}.</span>
                  <span className="text-sm font-medium flex-1">{opt?.label ?? id}</span>
                  <div className="flex flex-col shrink-0">
                    <button
                      onClick={() => moveRanked(index, index - 1)}
                      disabled={index === 0 || disabled}
                      className="text-muted-foreground hover:text-foreground disabled:opacity-30 text-xs p-0.5"
                    >
                      ▲
                    </button>
                    <button
                      onClick={() => moveRanked(index, index + 1)}
                      disabled={index === (ranked?.length ?? 0) - 1 || disabled}
                      className="text-muted-foreground hover:text-foreground disabled:opacity-30 text-xs p-0.5"
                    >
                      ▼
                    </button>
                  </div>
                </div>
              )
            })}
          </div>
        )}

        {/* Custom input */}
        {decision?.allow_custom && type !== 'ranked' && (
          <Textarea
            placeholder="Or type your own answer..."
            value={customInput}
            onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => setCustomInput(e.target.value)}
            rows={2}
            className="resize-none text-sm"
            disabled={disabled}
          />
        )}

        {/* Comment (collapsed by default) */}
        {showComment ? (
          <Textarea
            placeholder="Add a comment..."
            value={comment}
            onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => setComment(e.target.value)}
            rows={1}
            className="resize-none text-xs"
            disabled={disabled}
            autoFocus
          />
        ) : (
          <button
            onClick={() => setShowComment(true)}
            disabled={disabled}
            className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground transition-colors"
          >
            <MessageSquare className="h-3 w-3" />
            Add a comment
          </button>
        )}

        {/* Actions */}
        <div className="flex items-center gap-2">
          <Button
            size="sm"
            onClick={handleSubmit}
            disabled={disabled}
            className="h-7 text-xs px-3"
          >
            <Send className="mr-1.5 h-3 w-3" />
            Submit
          </Button>
          {decision?.allow_not_sure && (
            <Button
              variant="ghost"
              size="sm"
              onClick={handleNotSure}
              disabled={disabled}
              className="h-7 text-xs px-2 text-muted-foreground"
            >
              <HelpCircle className="mr-1 h-3 w-3" />
              Not sure
            </Button>
          )}
        </div>
      </CardContent>
    </Card>
  )
}

'use client';

import { useState, useEffect, useCallback, useMemo } from 'react';
import { Button } from '@/components/ui/button';
import { toast } from 'sonner';
import { FadeIn } from '@/components/ui/animate';
import { Layers, Plus, Trash2, Wand2, CheckCircle, ArrowLeft, Sparkles, Loader2 } from 'lucide-react';
import Link from 'next/link';
import {
  FeatureSplitListResponseSchema,
  FeatureSplitDTOSchema,
  type FeatureCluster,
  type FeatureSplitDTO,
} from '@repo/contracts/feature-split/feature-split';
import {
  PrdVersionListResponseSchema,
  type PrdVersionDTO,
} from '@repo/contracts/prd/prd-contracts';
import { ProposeFeatureSplitResponseSchema } from '@repo/contracts/ai/feature-split-proposal';
import {
  assessPrdSplitReadiness,
  buildTemplateClustersFromPrd,
} from '@/lib/prd-content-for-ai';

interface FeatureSplitWorkspaceProps {
  projectId: string;
  projectName: string;
}

interface ClusterDraft {
  sortOrder: number;
  label: string;
  valueLine: string;
  boundaryCue: string;
}

function emptyCluster(sortOrder: number): ClusterDraft {
  return { sortOrder, label: '', valueLine: '', boundaryCue: '' };
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

const PROPOSAL_STATUS_MESSAGES = [
  'Reading PRD sections…',
  'Identifying deliverable areas…',
  'Drafting cluster boundaries…',
] as const;

export function FeatureSplitWorkspace({ projectId, projectName }: FeatureSplitWorkspaceProps) {
  const [prdVersions, setPrdVersions] = useState<PrdVersionDTO[]>([]);
  const [selectedVersionId, setSelectedVersionId] = useState<string | null>(null);
  const [split, setSplit] = useState<FeatureSplitDTO | null>(null);
  const [clusters, setClusters] = useState<ClusterDraft[]>([emptyCluster(0)]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [proposing, setProposing] = useState(false);
  const [buildingTemplate, setBuildingTemplate] = useState(false);
  const [proposalStatus, setProposalStatus] = useState<string | null>(null);
  const [revealedClusterCount, setRevealedClusterCount] = useState<number | null>(null);
  const [confirming, setConfirming] = useState(false);

  const selectedVersion = useMemo(
    () => prdVersions.find((version) => version.id === selectedVersionId) ?? null,
    [prdVersions, selectedVersionId]
  );

  const prdReadiness = useMemo(
    () => (selectedVersion?.content ? assessPrdSplitReadiness(selectedVersion.content) : null),
    [selectedVersion]
  );

  const fetchVersions = useCallback(async () => {
    try {
      const res = await fetch(`/api/projects/${projectId}/prd`);
      if (!res.ok) return;
      const raw = await res.json();
      const parsed = PrdVersionListResponseSchema.safeParse(raw);
      if (!parsed.success) return;
      setPrdVersions(parsed.data);
      if (parsed.data.length > 0 && !selectedVersionId) {
        setSelectedVersionId(parsed.data[0].id);
      }
    } catch {
      // silent
    }
  }, [projectId, selectedVersionId]);

  const fetchSplit = useCallback(
    async (prdVersionId: string) => {
      setLoading(true);
      try {
        const res = await fetch(
          `/api/projects/${projectId}/feature-split?sourcePrdVersionId=${encodeURIComponent(prdVersionId)}`
        );
        if (!res.ok) {
          setSplit(null);
          setClusters([emptyCluster(0)]);
          return;
        }
        const raw = await res.json();
        const parsed = FeatureSplitListResponseSchema.safeParse(raw);
        if (!parsed.success || parsed.data.length === 0) {
          setSplit(null);
          setClusters([emptyCluster(0)]);
          return;
        }
        const existing = parsed.data[0];
        setSplit(existing);
        setClusters(
          existing.clusters.length > 0
            ? existing.clusters.map((c: FeatureCluster) => ({
                sortOrder: c.sortOrder,
                label: c.label,
                valueLine: c.valueLine,
                boundaryCue: c.boundaryCue,
              }))
            : [emptyCluster(0)]
        );
      } catch {
        setSplit(null);
      } finally {
        setLoading(false);
      }
    },
    [projectId]
  );

  useEffect(() => {
    fetchVersions();
  }, [fetchVersions]);

  useEffect(() => {
    if (selectedVersionId) {
      fetchSplit(selectedVersionId);
    }
  }, [selectedVersionId, fetchSplit]);

  const handleAddCluster = () => {
    setClusters((prev) => [...prev, emptyCluster(prev.length)]);
  };

  const handleRemoveCluster = (index: number) => {
    setClusters((prev) =>
      prev
        .filter((_, i) => i !== index)
        .map((c, i) => ({ ...c, sortOrder: i }))
    );
  };

  const handleClusterChange = (
    index: number,
    field: keyof ClusterDraft,
    value: string | number
  ) => {
    setClusters((prev) => prev.map((c, i) => (i === index ? { ...c, [field]: value } : c)));
  };

  const revealClustersSequentially = async (nextClusters: ClusterDraft[]) => {
    setClusters([]);
    setRevealedClusterCount(0);

    for (let index = 0; index < nextClusters.length; index++) {
      setProposalStatus(`Cluster ${index + 1} of ${nextClusters.length} ready`);
      await sleep(220);
      setClusters((prev) => [...prev, nextClusters[index]]);
      setRevealedClusterCount(index + 1);
    }

    setProposalStatus(null);
    setRevealedClusterCount(null);
  };

  const handleBuildFromSections = async () => {
    if (!selectedVersion?.content) {
      toast.error('No PRD content found for this version');
      return;
    }

    const template = buildTemplateClustersFromPrd(selectedVersion.content);
    if (template.length === 0) {
      toast.error('No filled PRD sections to convert. Complete the PRD in the workspace first.');
      return;
    }

    setBuildingTemplate(true);
    try {
      await revealClustersSequentially(template);
      toast.success(`${template.length} clusters loaded from PRD sections — edit each field`);
    } finally {
      setBuildingTemplate(false);
    }
  };

  const handlePropose = async () => {
    if (!selectedVersionId) return;

    if (prdReadiness && !prdReadiness.isReadyForAiSplit) {
      toast.error(prdReadiness.message);
      return;
    }

    setProposing(true);
    setProposalStatus(PROPOSAL_STATUS_MESSAGES[0]);
    const statusTimer = window.setInterval(() => {
      setProposalStatus((current) => {
        const index = PROPOSAL_STATUS_MESSAGES.indexOf(
          (current ?? PROPOSAL_STATUS_MESSAGES[0]) as (typeof PROPOSAL_STATUS_MESSAGES)[number]
        );
        const nextIndex = index < 0 ? 0 : (index + 1) % PROPOSAL_STATUS_MESSAGES.length;
        return PROPOSAL_STATUS_MESSAGES[nextIndex];
      });
    }, 2500);

    try {
      const res = await fetch(`/api/projects/${projectId}/feature-split/propose`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sourcePrdVersionId: selectedVersionId }),
      });
      const raw = await res.json();
      if (!res.ok) {
        if (res.status === 402) {
          toast.error('Insufficient credits for AI proposal');
        } else if (res.status === 504) {
          toast.error('AI request timed out. Try again or shorten your PRD.');
        } else if (res.status === 503) {
          toast.error('AI provider is not configured on this server.');
        } else if (res.status === 400 || res.status === 422) {
          toast.error(raw?.error ?? 'PRD is not ready for AI splitting');
        } else {
          toast.error(raw?.error ?? 'AI proposal failed');
        }
        return;
      }
      const parsed = ProposeFeatureSplitResponseSchema.safeParse(raw);
      if (!parsed.success) {
        toast.error('Unexpected response from AI');
        return;
      }
      const proposal = parsed.data.proposal;
      const mapped = proposal.clusters.map((cluster) => ({
        sortOrder: cluster.sortOrder,
        label: cluster.label,
        valueLine: cluster.valueLine,
        boundaryCue: cluster.boundaryCue,
      }));
      await revealClustersSequentially(mapped);
      toast.success('AI proposal loaded — review each cluster, then save as draft');
    } catch {
      toast.error('Network error during AI proposal');
    } finally {
      window.clearInterval(statusTimer);
      setProposalStatus(null);
      setProposing(false);
    }
  };

  const handleSaveDraft = async () => {
    if (!selectedVersionId) return;
    const validClusters = clusters.filter(
      (c) => c.label.trim() && c.valueLine.trim() && c.boundaryCue.trim()
    );
    if (validClusters.length === 0) {
      toast.error('Add at least one complete cluster before saving');
      return;
    }
    setSaving(true);
    try {
      const res = await fetch(`/api/projects/${projectId}/feature-split`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          sourcePrdVersionId: selectedVersionId,
          clusters: validClusters,
        }),
      });
      const raw = await res.json();
      if (!res.ok) {
        toast.error(raw?.error ?? 'Failed to save draft');
        return;
      }
      const parsed = FeatureSplitDTOSchema.safeParse(raw);
      if (!parsed.success) {
        toast.error('Unexpected response');
        return;
      }
      setSplit(parsed.data);
      toast.success('Draft saved');
    } catch {
      toast.error('Network error while saving');
    } finally {
      setSaving(false);
    }
  };

  const handleConfirm = async () => {
    if (!split) return;
    setConfirming(true);
    try {
      const res = await fetch(`/api/projects/${projectId}/feature-split/confirm`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ featureSplitId: split.id }),
      });
      const raw = await res.json();
      if (!res.ok) {
        toast.error(raw?.error ?? 'Failed to confirm');
        return;
      }
      const parsed = FeatureSplitDTOSchema.safeParse(raw);
      if (parsed.success) setSplit(parsed.data);
      toast.success('Feature split confirmed');
    } catch {
      toast.error('Network error while confirming');
    } finally {
      setConfirming(false);
    }
  };

  const isConfirmed = split?.status === 'confirmed';

  return (
    <div className="min-h-screen bg-background">
      <div className="max-w-3xl mx-auto px-4 py-8 sm:px-6">
        {/* Header */}
        <div className="mb-6">
          <Link
            href={`/dashboard/projects/${projectId}`}
            className="inline-flex items-center gap-1 text-sm text-muted-foreground hover:text-foreground mb-4"
          >
            <ArrowLeft className="h-4 w-4" />
            Back to {projectName}
          </Link>
          <div className="flex items-center gap-3">
            <Layers className="h-6 w-6 text-primary" />
            <div>
              <h1 className="text-xl font-semibold">Feature Split</h1>
              <p className="text-sm text-muted-foreground">
                Break your PRD into independently deliverable clusters.
              </p>
            </div>
          </div>
        </div>

        {/* PRD version picker */}
        {prdVersions.length > 1 && (
          <div className="mb-4">
            <label className="text-sm font-medium mb-1 block">PRD version</label>
            <select
              className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
              value={selectedVersionId ?? ''}
              onChange={(e) => setSelectedVersionId(e.target.value)}
            >
              {prdVersions.map((v) => (
                <option key={v.id} value={v.id}>
                  v{v.versionNumber}
                  {v.status ? ` — ${v.status}` : ''}
                </option>
              ))}
            </select>
          </div>
        )}

        {/* Status badge */}
        {split && (
          <div className="mb-4 flex items-center gap-2">
            <span
              className={`inline-flex items-center gap-1 text-xs px-2 py-1 rounded-full font-medium ${
                isConfirmed
                  ? 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-300'
                  : 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-300'
              }`}
            >
              {isConfirmed ? (
                <>
                  <CheckCircle className="h-3 w-3" />
                  Confirmed
                </>
              ) : (
                'Draft'
              )}
            </span>
            <span className="text-xs text-muted-foreground">
              {split.clusters.length} cluster{split.clusters.length !== 1 ? 's' : ''}
            </span>
          </div>
        )}

        {/* Loading */}
        {loading && (
          <div className="py-12 text-center text-muted-foreground text-sm">Loading…</div>
        )}

        {!loading && (
          <FadeIn>
            {prdReadiness && !prdReadiness.isReadyForAiSplit && (
              <div className="mb-6 rounded-md border border-amber-500/30 bg-amber-500/5 p-4 text-sm">
                <p className="font-medium text-foreground">PRD not ready for AI split</p>
                <p className="text-muted-foreground mt-1">{prdReadiness.message}</p>
                <div className="mt-3 flex flex-wrap gap-2">
                  <Button asChild variant="outline" size="sm" className="min-h-[44px]">
                    <Link href={`/dashboard/projects/${projectId}`}>Open project workspace</Link>
                  </Button>
                  <Button
                    type="button"
                    variant="secondary"
                    size="sm"
                    className="min-h-[44px]"
                    disabled={buildingTemplate}
                    onClick={() => void handleBuildFromSections()}
                  >
                    {buildingTemplate ? <Loader2 className="h-4 w-4 animate-spin" /> : <Sparkles className="h-4 w-4" />}
                    <span className="ml-2">From PRD sections</span>
                  </Button>
                </div>
              </div>
            )}

            {(proposing || buildingTemplate || proposalStatus) && (
              <div className="mb-6 rounded-md border bg-muted/30 p-4 text-sm flex items-center gap-3">
                <Loader2 className="h-4 w-4 animate-spin shrink-0 text-primary" />
                <span>{proposalStatus ?? 'Preparing clusters…'}</span>
              </div>
            )}

            {/* Actions */}
            {!isConfirmed && (
              <div className="flex flex-wrap gap-2 mb-6">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => void handlePropose()}
                  disabled={proposing || buildingTemplate || !selectedVersionId || !prdReadiness?.isReadyForAiSplit}
                >
                  <Wand2 className="h-4 w-4 mr-1" />
                  {proposing ? 'Generating…' : 'AI propose'}
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => void handleBuildFromSections()}
                  disabled={proposing || buildingTemplate || !selectedVersion?.content}
                >
                  <Sparkles className="h-4 w-4 mr-1" />
                  {buildingTemplate ? 'Building…' : 'From PRD sections'}
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleAddCluster}
                  disabled={proposing || buildingTemplate}
                >
                  <Plus className="h-4 w-4 mr-1" />
                  Add cluster
                </Button>
              </div>
            )}

            {/* Cluster list */}
            <div className="space-y-4">
              {clusters.map((cluster, index) => {
                const isRevealing =
                  revealedClusterCount != null && index === revealedClusterCount - 1;
                return (
                <div
                  key={`${cluster.sortOrder}-${index}`}
                  className={`border border-border rounded-lg p-4 space-y-3 bg-card transition-all duration-300 ${
                    isRevealing ? 'ring-2 ring-primary/30' : ''
                  }`}
                >
                  <div className="flex items-center justify-between">
                    <span className="text-xs font-medium text-muted-foreground uppercase tracking-wide">
                      Cluster {index + 1}
                    </span>
                    {!isConfirmed && clusters.length > 1 && (
                      <button
                        type="button"
                        onClick={() => handleRemoveCluster(index)}
                        className="text-muted-foreground hover:text-destructive transition-colors p-1"
                        aria-label="Remove cluster"
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    )}
                  </div>

                  <div>
                    <label className="text-xs font-medium mb-1 block">Name</label>
                    <input
                      type="text"
                      className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm disabled:opacity-60"
                      placeholder="e.g. Payments"
                      value={cluster.label}
                      onChange={(e) => handleClusterChange(index, 'label', e.target.value)}
                      disabled={isConfirmed}
                      maxLength={500}
                    />
                  </div>

                  <div>
                    <label className="text-xs font-medium mb-1 block">Value</label>
                    <input
                      type="text"
                      className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm disabled:opacity-60"
                      placeholder="What user value does this cluster deliver?"
                      value={cluster.valueLine}
                      onChange={(e) => handleClusterChange(index, 'valueLine', e.target.value)}
                      disabled={isConfirmed}
                      maxLength={2000}
                    />
                  </div>

                  <div>
                    <label className="text-xs font-medium mb-1 block">Boundary</label>
                    <input
                      type="text"
                      className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm disabled:opacity-60"
                      placeholder="What does this cluster NOT include?"
                      value={cluster.boundaryCue}
                      onChange={(e) => handleClusterChange(index, 'boundaryCue', e.target.value)}
                      disabled={isConfirmed}
                      maxLength={2000}
                    />
                  </div>
                </div>
                );
              })}
            </div>

            {/* Footer actions */}
            {!isConfirmed && (
              <div className="mt-6 flex flex-col sm:flex-row gap-3">
                <Button
                  onClick={handleSaveDraft}
                  disabled={saving}
                  className="flex-1 sm:flex-none"
                >
                  {saving ? 'Saving…' : 'Save draft'}
                </Button>
                {split && (
                  <Button
                    variant="default"
                    onClick={handleConfirm}
                    disabled={confirming}
                    className="flex-1 sm:flex-none bg-green-600 hover:bg-green-700"
                  >
                    <CheckCircle className="h-4 w-4 mr-1" />
                    {confirming ? 'Confirming…' : 'Confirm split'}
                  </Button>
                )}
              </div>
            )}

            {isConfirmed && (
              <div className="mt-6 p-4 rounded-lg bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800">
                <p className="text-sm text-green-800 dark:text-green-300 font-medium">
                  Feature split confirmed. The next step is generating user stories from these clusters.
                </p>
              </div>
            )}
          </FadeIn>
        )}
      </div>
    </div>
  );
}

'use client'

import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
} from 'react'
import { usePathname, useRouter } from 'next/navigation'
import { OwnerMilestoneDetectedPayloadSchema } from '@repo/contracts/feedback/milestone-prompt'
import type { OwnerMilestoneDetectedPayload } from '@repo/contracts/feedback/milestone-prompt'
import { OwnerMilestoneTypeSchema } from '@repo/contracts/feedback/submit'
import type { OwnerMilestoneType } from '@repo/contracts/feedback/submit'
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert'
import { Button } from '@/components/ui/button'
import { MilestoneFeedbackModal } from '@/components/milestone-feedback-modal'

const STORAGE_PREFIX = 'zedos:owner-milestone-banner:'

function dedupeStorageKey(payload: OwnerMilestoneDetectedPayload): string {
  const v = payload.prdVersionId ?? '_'
  return `${STORAGE_PREFIX}${payload.projectId}:${payload.milestoneType}:${v}`
}

function bannerCopy(milestoneType: OwnerMilestoneType): { title: string; description: string } {
  switch (milestoneType) {
    case 'prd_created':
      return {
        title: 'PRD created',
        description: 'If you have a moment, tell us how the generation flow worked for you.',
      }
    case 'prd_updated':
      return {
        title: 'PRD updated',
        description: 'Quick feedback on the update experience helps us improve.',
      }
    case 'prd_shared':
      return {
        title: 'Share link ready',
        description: 'How was sharing your PRD with stakeholders?',
      }
    case 'prd_viewed':
      return {
        title: 'Reviewing your PRD',
        description: 'We would love a quick rating of the reading experience.',
      }
    default:
      return { title: 'Milestone', description: 'Share quick feedback if you would like.' }
  }
}

function modalCopy(milestoneType: OwnerMilestoneType): { title: string; description: string } {
  switch (milestoneType) {
    case 'prd_created':
      return {
        title: 'PRD generated',
        description: 'Your feedback helps improve the product clarification experience.',
      }
    case 'prd_shared':
      return {
        title: 'PRD shared',
        description: 'Your feedback helps improve sharing and collaboration.',
      }
    case 'prd_updated':
      return {
        title: 'PRD updated',
        description: 'Your feedback helps improve refinement and update flows.',
      }
    case 'prd_viewed':
      return {
        title: 'PRD reading experience',
        description: 'Your feedback helps improve how PRDs are presented in the workspace.',
      }
    default:
      return {
        title: 'How was that?',
        description: 'Your feedback helps us improve the product.',
      }
  }
}

type MilestonePromptContextValue = {
  notifyMilestone: (input: unknown) => void
}

const MilestonePromptContext = createContext<MilestonePromptContextValue | null>(null)

export function useOwnerMilestonePrompt(): MilestonePromptContextValue {
  const ctx = useContext(MilestonePromptContext)
  if (!ctx) {
    return { notifyMilestone: () => {} }
  }
  return ctx
}

export function OwnerMilestonePromptProvider({
  children,
  projectId,
  enabled,
}: {
  children: React.ReactNode
  projectId: string
  enabled: boolean
}) {
  const router = useRouter()
  const pathname = usePathname()
  const [bannerPayload, setBannerPayload] = useState<OwnerMilestoneDetectedPayload | null>(null)
  const [modalOpen, setModalOpen] = useState(false)
  const [modalPayload, setModalPayload] = useState<OwnerMilestoneDetectedPayload | null>(null)

  const tryShow = useCallback(
    (payload: OwnerMilestoneDetectedPayload) => {
      if (!enabled || payload.projectId !== projectId) return
      if (typeof sessionStorage === 'undefined') return
      const key = dedupeStorageKey(payload)
      if (sessionStorage.getItem(key)) return
      setBannerPayload(payload)
    },
    [enabled, projectId]
  )

  const notifyMilestone = useCallback(
    (input: unknown) => {
      if (!enabled) return
      const parsed = OwnerMilestoneDetectedPayloadSchema.safeParse(input)
      if (!parsed.success) return
      tryShow(parsed.data)
    },
    [enabled, tryShow]
  )

  useEffect(() => {
    if (!enabled || typeof window === 'undefined') return
    const params = new URLSearchParams(window.location.search)
    const rawType = params.get('om')
    const rawVersion = params.get('omv')
    if (!rawType) return

    const typeParsed = OwnerMilestoneTypeSchema.safeParse(rawType)
    if (!typeParsed.success) return

    const candidate: OwnerMilestoneDetectedPayload = {
      projectId,
      milestoneType: typeParsed.data,
      ...(rawVersion && rawVersion.length > 0 ? { prdVersionId: rawVersion } : {}),
    }
    const validated = OwnerMilestoneDetectedPayloadSchema.safeParse(candidate)
    if (!validated.success) return

    tryShow(validated.data)

    params.delete('om')
    params.delete('omv')
    const next = params.toString()
    const url = next ? `${pathname}?${next}` : pathname
    router.replace(url)
  }, [enabled, pathname, projectId, router, tryShow])

  const skipBanner = useCallback(() => {
    if (bannerPayload && typeof sessionStorage !== 'undefined') {
      sessionStorage.setItem(dedupeStorageKey(bannerPayload), '1')
    }
    setBannerPayload(null)
  }, [bannerPayload])

  const openModalFromBanner = useCallback(() => {
    if (!bannerPayload) return
    setModalPayload(bannerPayload)
    setModalOpen(true)
    setBannerPayload(null)
  }, [bannerPayload])

  const closeModal = useCallback(() => {
    setModalOpen(false)
    if (modalPayload && typeof sessionStorage !== 'undefined') {
      sessionStorage.setItem(dedupeStorageKey(modalPayload), '1')
    }
    setModalPayload(null)
  }, [modalPayload])

  const ctx = useMemo(() => ({ notifyMilestone }), [notifyMilestone])

  const bannerText = bannerPayload ? bannerCopy(bannerPayload.milestoneType) : null
  const modalText = modalPayload ? modalCopy(modalPayload.milestoneType) : null

  return (
    <MilestonePromptContext.Provider value={ctx}>
      {children}
      {enabled && bannerPayload && bannerText && (
        <div className="fixed bottom-0 left-0 right-0 z-50 p-3 sm:p-4 pointer-events-none">
          <Alert className="pointer-events-auto max-w-3xl mx-auto border-primary/20 bg-background/95 shadow-lg backdrop-blur-sm">
            <AlertTitle className="text-base font-display pr-8">{bannerText.title}</AlertTitle>
            <AlertDescription className="text-sm text-muted-foreground mt-1">
              {bannerText.description}
            </AlertDescription>
            <div className="flex flex-wrap gap-2 mt-3 justify-end">
              <Button type="button" variant="ghost" size="sm" className="min-h-[44px]" onClick={skipBanner}>
                Skip
              </Button>
              <Button type="button" size="sm" className="min-h-[44px]" onClick={openModalFromBanner}>
                Share feedback
              </Button>
            </div>
          </Alert>
        </div>
      )}
      {modalPayload && modalText && (
        <MilestoneFeedbackModal
          open={modalOpen}
          onClose={closeModal}
          projectId={modalPayload.projectId}
          prdVersionId={modalPayload.prdVersionId ?? null}
          milestoneType={modalPayload.milestoneType}
          title={modalText.title}
          description={modalText.description}
        />
      )}
    </MilestonePromptContext.Provider>
  )
}

'use client'

import { useState, useEffect } from 'react'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import {
  FileText, Share2, Copy, Check, XCircle,
  AlertCircle, CheckCircle2, CircleDot, MessageSquare,
} from 'lucide-react'
import { toast } from 'sonner'
import { MilestoneFeedbackModal } from '@/components/milestone-feedback-modal'
import { FadeIn, Stagger, StaggerItem } from '@/components/ui/animate'
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert'
import type { PrdVersionDTO } from '@repo/contracts/prd/prd-contracts'
import { ShareLinkMintResponseSchema, ShareLinkSummarySchema } from '@repo/contracts/share/mint'
import { useOwnerMilestonePrompt } from './owner-milestone-prompt'

interface PrdViewerProps {
  projectId: string
  versions: PrdVersionDTO[]
  selectedVersion: PrdVersionDTO | null
  onSelectVersion: (v: PrdVersionDTO) => void
  onRefresh: () => void
  onOpenRefinement?: (payload: { label: string; prdVersionId: string | null }) => void
}

export function PrdViewer({
  projectId,
  versions,
  selectedVersion,
  onSelectVersion,
  onRefresh,
  onOpenRefinement,
}: PrdViewerProps) {
  const { notifyMilestone } = useOwnerMilestonePrompt()
  const [shareLink, setShareLink] = useState<string | null>(null)
  const [shareLinkObj, setShareLinkObj] = useState<
    { id: string; token: string; enabled: boolean } | null
  >(null)
  const [sharing, setSharing] = useState(false)
  const [copied, setCopied] = useState(false)
  const [showFeedback, setShowFeedback] = useState(false)
  const [feedbackType, setFeedbackType] = useState('')

  // Check for existing share link
  useEffect(() => {
    const existing = selectedVersion?.shareLinks?.[0]
    const summary = existing ? ShareLinkSummarySchema.safeParse(existing) : null
    if (summary?.success && summary.data.token) {
      const { id, token, enabled } = summary.data
      setShareLink(`${window?.location?.origin ?? ''}/share/${token}`)
      setShareLinkObj({ id, token, enabled })
    } else {
      setShareLink(null)
      setShareLinkObj(null)
    }
  }, [selectedVersion])

  useEffect(() => {
    if (!selectedVersion?.id) return
    notifyMilestone({
      projectId,
      milestoneType: 'prd_viewed',
      prdVersionId: selectedVersion.id,
    })
  }, [projectId, selectedVersion?.id, notifyMilestone])

  const content = selectedVersion?.content as Record<string, unknown> & {
    title?: string
    sections?: unknown[]
    version_summary?: string
 }
  const sections = content?.sections ?? []

  const handleShare = async () => {
    if (!selectedVersion?.id) return
    setSharing(true)
    try {
      const res = await fetch('/api/share/create', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ prdVersionId: selectedVersion.id }),
      })
      if (res?.ok) {
        const raw = await res.json()
        const validated = ShareLinkMintResponseSchema.safeParse(raw)
        if (!validated.success) {
          toast.error('Invalid share link response')
          return
        }
        const data = validated.data
        const link = `${window?.location?.origin ?? ''}/share/${data.token}`
        setShareLink(link)
        setShareLinkObj({ id: data.id, token: data.token, enabled: data.enabled })
        toast.success('Share link created!')
        // Milestone feedback for sharing
        setFeedbackType('prd_shared')
        setShowFeedback(true)
        notifyMilestone({
          projectId,
          milestoneType: 'prd_shared',
          prdVersionId: selectedVersion.id,
        })
      } else {
        let msg = 'Failed to create share link'
        try {
          const errBody = (await res.json()) as { error?: string }
          if (errBody?.error) msg = errBody.error
        } catch {
          /* ignore */
        }
        toast.error(msg)
      }
    } catch {
      toast.error('Failed to create share link')
    } finally {
      setSharing(false)
    }
  }

  const handleDisableShare = async () => {
    if (!shareLinkObj?.id) return
    try {
      await fetch('/api/share/disable', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ shareLinkId: shareLinkObj.id }),
      })
      setShareLink(null)
      setShareLinkObj(null)
      toast.success('Share link disabled')
      onRefresh()
    } catch {
      toast.error('Failed to disable share link')
    }
  }

  const handleCopy = () => {
    if (shareLink) {
      navigator?.clipboard?.writeText?.(shareLink)
      setCopied(true)
      setTimeout(() => setCopied(false), 2000)
      toast.success('Copied to clipboard')
    }
  }

  const getConfidenceColor = (confidence: string) => {
    switch (confidence) {
      case 'high': return 'text-green-600 bg-green-50'
      case 'medium': return 'text-amber-600 bg-amber-50'
      case 'low': return 'text-red-500 bg-red-50'
      default: return 'text-muted-foreground bg-muted'
    }
  }

  const getConfidenceIcon = (confidence: string) => {
    switch (confidence) {
      case 'high': return <CheckCircle2 className="h-3.5 w-3.5" />
      case 'medium': return <CircleDot className="h-3.5 w-3.5" />
      case 'low': return <AlertCircle className="h-3.5 w-3.5" />
      default: return null
    }
  }

  if ((versions?.length ?? 0) === 0) {
    return (
      <Card className="border-dashed">
        <CardContent className="flex flex-col items-center justify-center py-16">
          <FileText className="h-12 w-12 text-muted-foreground/30 mb-4" />
          <h3 className="font-display text-lg font-semibold mb-1">No PRD yet</h3>
          <p className="text-sm text-muted-foreground text-center max-w-md">
            Go through the clarification flow and generate your first PRD version.
          </p>
        </CardContent>
      </Card>
    )
  }

  return (
    <div className="space-y-4">
      {/* Version selector + actions */}
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div className="flex flex-col sm:flex-row sm:items-center gap-2 sm:gap-3 w-full sm:w-auto">
          <Select
            value={selectedVersion?.id ?? ''}
            onValueChange={(id: string) => {
              const v = versions.find((x) => x.id === id)
              if (v) onSelectVersion(v)
            }}
          >
            <SelectTrigger className="w-full sm:w-48 min-h-11 text-base" aria-label="PRD version">
              <SelectValue placeholder="Select version" />
            </SelectTrigger>
            <SelectContent>
              {(versions ?? []).map((v) => (
                <SelectItem key={v.id} value={v.id} className="min-h-11 text-base">
                  Version {v.versionNumber}
                  {v.status ? ` (${v.status})` : ''}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
          {content?.title && (
            <h2 className="font-display text-lg font-semibold hidden sm:block">{content.title}</h2>
          )}
        </div>

        <div className="flex items-center gap-2 shrink-0">
          {onOpenRefinement && selectedVersion && (
            <Button
              variant="ghost"
              size="sm"
              onClick={() => onOpenRefinement({ label: 'my PRD', prdVersionId: selectedVersion?.id ?? null })}
              title="Open a focused chat to refine this PRD"
            >
              <MessageSquare className="mr-2 h-3.5 w-3.5" />
              Refine PRD
            </Button>
          )}
          {shareLink ? (
            <div className="flex items-center gap-1">
              <Button variant="outline" size="sm" onClick={handleCopy}>
                {copied ? <Check className="mr-1 h-3.5 w-3.5" /> : <Copy className="mr-1 h-3.5 w-3.5" />}
                {copied ? 'Copied' : 'Copy Link'}
              </Button>
              <Button variant="ghost" size="sm" onClick={handleDisableShare} className="text-destructive">
                <XCircle className="mr-1 h-3.5 w-3.5" />
                Disable
              </Button>
            </div>
          ) : (
            <Button variant="outline" size="sm" onClick={handleShare} loading={sharing}>
              <Share2 className="mr-2 h-3.5 w-3.5" />
              Share
            </Button>
          )}
        </div>
      </div>

      <Alert className="border-primary/20 bg-primary/5">
        <FileText className="h-4 w-4" />
        <AlertTitle className="text-sm font-medium leading-snug">
          Active version: {selectedVersion ? `v${selectedVersion.versionNumber}` : '—'}
          {selectedVersion?.status ? ` · ${selectedVersion.status}` : ''}
        </AlertTitle>
        <AlertDescription className="text-xs text-muted-foreground sm:text-sm mt-0.5">
          {versions.length > 1
            ? `This project has ${versions.length} versions. Pick one above — Clarify and sharing use the version shown here.`
            : 'You are viewing the only PRD version for this project.'}
        </AlertDescription>
      </Alert>

      {/* Version summary */}
      {content?.version_summary && (
        <FadeIn>
          <Card className="bg-muted/30">
            <CardContent className="p-4">
              <p className="text-sm text-muted-foreground">{content.version_summary}</p>
            </CardContent>
          </Card>
        </FadeIn>
      )}

      {/* PRD Sections */}
      <Stagger staggerDelay={0.05}>
        <div className="space-y-3">
          {(sections ?? []).map((section: any, i: number) => (
            <StaggerItem key={section?.id ?? i}>
              <Card className="group">
                <CardHeader className="pb-2">
                  <div className="flex items-start justify-between gap-2">
                    <CardTitle className="text-base font-display pr-1 flex-1 min-w-0">
                      {section?.title ?? 'Section'}
                    </CardTitle>
                    <div className="flex items-center gap-1.5 shrink-0">
                      {onOpenRefinement ? (
                        <Button
                          type="button"
                          variant="ghost"
                          size="icon"
                          className="h-11 w-11 sm:h-9 sm:w-9 text-muted-foreground hover:text-foreground"
                          aria-label={`Refine section ${section?.title ?? 'Section'}`}
                          onClick={() =>
                            onOpenRefinement({
                              label: `${section?.title ?? 'Section'} (PRD)`,
                              prdVersionId: selectedVersion?.id ?? null,
                            })
                          }
                        >
                          <MessageSquare className="h-4 w-4" />
                        </Button>
                      ) : null}
                      {section?.confidence && (
                        <Badge
                          variant="secondary"
                          className={`text-xs gap-1 shrink-0 ${getConfidenceColor(section.confidence)}`}
                        >
                          {getConfidenceIcon(section.confidence)}
                          {section.confidence}
                        </Badge>
                      )}
                    </div>
                  </div>
                </CardHeader>
                <CardContent className="space-y-3">
                  <div className="text-sm whitespace-pre-wrap leading-relaxed">
                    {section?.content ?? 'No content'}
                  </div>
                  {(section?.open_questions?.length ?? 0) > 0 && (
                    <div className="bg-amber-50 dark:bg-amber-950/20 rounded-lg p-3">
                      <p className="text-xs font-medium text-amber-700 dark:text-amber-400 mb-1">Open Questions</p>
                      <ul className="text-xs text-amber-600 dark:text-amber-300 space-y-1">
                        {(section.open_questions ?? []).map((q: string, qi: number) => (
                          <li key={qi} className="flex items-start gap-1.5">
                            <span className="mt-0.5">•</span>
                            <span>{q}</span>
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}
                </CardContent>
              </Card>
            </StaggerItem>
          ))}
        </div>
      </Stagger>

      {/* Raw content fallback */}
      {(sections?.length ?? 0) === 0 && content && (
        <Card>
          <CardContent className="p-4">
            <pre className="text-sm whitespace-pre-wrap font-mono">
              {typeof content === 'string' ? content : JSON.stringify(content, null, 2)}
            </pre>
          </CardContent>
        </Card>
      )}

      {/* Milestone Feedback */}
      <MilestoneFeedbackModal
        open={showFeedback}
        onClose={() => setShowFeedback(false)}
        projectId={projectId}
        prdVersionId={selectedVersion?.id}
        milestoneType={feedbackType}
        title={
          feedbackType === 'prd_shared'
            ? 'PRD Shared!'
            : feedbackType === 'prd_reopened'
            ? 'Welcome back to your PRD'
            : 'How was that?'
        }
        description="Quick feedback helps improve the experience."
      />
    </div>
  )
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/components/ui/tabs'
import { ClarificationChat } from './clarification-chat'
import { PrdViewer } from './prd-viewer'
import { QuestionHistoryPanel } from './question-history'
import { ArchitecturePanel } from './architecture-panel'
import { ReadinessScoreBadge } from './readiness-score-badge'
import { ContextualRefinementPanel } from './contextual-refinement-panel'
import { MessageSquare, FileText, History, Settings, Layers } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog'
import { toast } from 'sonner'
import { FadeIn } from '@/components/ui/animate'
import {
  PrdVersionListResponseSchema,
  type PrdVersionDTO,
} from '@repo/contracts/prd/prd-contracts'

interface ProjectWorkspaceProps {
  projectId: string
  projectName: string
  projectDescription: string | null
}

export function ProjectWorkspace({ projectId, projectName, projectDescription }: ProjectWorkspaceProps) {
  const [activeTab, setActiveTab] = useState('clarify')
  const [prdVersions, setPrdVersions] = useState<PrdVersionDTO[]>([])
  const [selectedVersion, setSelectedVersion] = useState<PrdVersionDTO | null>(null)
  const [showSettings, setShowSettings] = useState(false)
  const [editName, setEditName] = useState(projectName ?? '')
  const [editDesc, setEditDesc] = useState(projectDescription ?? '')
  const [saving, setSaving] = useState(false)
  const [phase, setPhase] = useState('intake')
  const [loadingPhase, setLoadingPhase] = useState(true)
  const [refinement, setRefinement] = useState<{
    isOpen: boolean
    label: string
    prdVersionId: string | null
  }>({ isOpen: false, label: '', prdVersionId: null })

  const openRefinement = useCallback((payload: { label: string; prdVersionId: string | null }) => {
    setRefinement({ isOpen: true, ...payload })
  }, [])

  const closeRefinement = useCallback(() => {
    setRefinement((r) => ({ ...r, isOpen: false }))
  }, [])

  const fetchVersions = useCallback(async () => {
    try {
      const ensure = await fetch(`/api/projects/${projectId}/prd`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({}),
      })
      if (!ensure.ok) {
        if (ensure.status !== 401) toast.error('Could not initialize PRD version')
        return
      }
      const res = await fetch(`/api/projects/${projectId}/prd`)
      if (res?.ok) {
        const raw = await res.json()
        const parsed = PrdVersionListResponseSchema.safeParse(raw)
        if (!parsed.success) {
          toast.error('Could not load PRD versions')
          return
        }
        const data = parsed.data
        setPrdVersions(data)
        setSelectedVersion((prev) => {
          if (prev && data.some((v) => v.id === prev.id)) return prev
          return data[0] ?? null
        })
      }
    } catch {
      toast.error('Could not load PRD versions')
    }
  }, [projectId])

  useEffect(() => {
    fetchVersions()
  }, [fetchVersions])

  useEffect(() => {
    const fetchPhase = async () => {
      try {
        const res = await fetch(`/api/projects/${projectId}`)
        if (res?.ok) {
          const data = await res.json()
          setPhase(data.phase || 'intake')
        }
      } catch {
      } finally {
        setLoadingPhase(false)
      }
    }
    fetchPhase()
  }, [projectId])

  const handlePrdGenerated = useCallback(() => {
    fetchVersions()
    setActiveTab('prd')
  }, [fetchVersions])

  const handleSaveSettings = async () => {
    setSaving(true)
    try {
      const res = await fetch(`/api/projects/${projectId}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: editName, description: editDesc }),
      })
      if (res?.ok) {
        toast.success('Project updated')
        setShowSettings(false)
      }
    } catch {
      toast.error('Failed to update project')
    } finally {
      setSaving(false)
    }
  }

  return (
    <div className="max-w-6xl mx-auto space-y-4">
      <FadeIn>
        <div className="flex items-center justify-between">
          <div>
            <h1 className="font-display text-2xl font-bold tracking-tight">{projectName}</h1>
            {projectDescription && (
              <p className="text-sm text-muted-foreground mt-0.5">{projectDescription}</p>
            )}
          </div>
          <Button variant="ghost" size="icon" onClick={() => setShowSettings(true)}>
            <Settings className="h-4 w-4" />
          </Button>
        </div>
      </FadeIn>

      <Tabs value={activeTab} onValueChange={setActiveTab}>
        <div className="flex items-center justify-between mb-4">
          <TabsList>
            <TabsTrigger value="clarify" className="gap-2">
              <MessageSquare className="h-4 w-4" />
              Clarify
            </TabsTrigger>
            <TabsTrigger value="prd" className="gap-2 min-h-11 sm:min-h-0">
              <FileText className="h-4 w-4" />
              PRD
              {selectedVersion && (
                <span
                  className="ml-1 text-xs bg-muted rounded-full px-1.5 py-0.5 font-mono"
                  title="Active PRD version in this workspace"
                >
                  v{selectedVersion.versionNumber}
                </span>
              )}
            </TabsTrigger>
            <TabsTrigger value="architecture" className="gap-2">
              <Layers className="h-4 w-4" />
              Architecture
            </TabsTrigger>
            <TabsTrigger value="history" className="gap-2">
              <History className="h-4 w-4" />
              History
            </TabsTrigger>
          </TabsList>
          {!loadingPhase && <ReadinessScoreBadge projectId={projectId} />}
        </div>

        <TabsContent value="clarify" className="mt-4">
          <ClarificationChat
            projectId={projectId}
            prdVersionId={selectedVersion?.id ?? null}
            onPrdGenerated={handlePrdGenerated}
          />
        </TabsContent>

        <TabsContent value="prd" className="mt-4">
          <PrdViewer
            projectId={projectId}
            versions={prdVersions}
            selectedVersion={selectedVersion}
            onSelectVersion={setSelectedVersion}
            onRefresh={fetchVersions}
            onOpenRefinement={openRefinement}
          />
        </TabsContent>

        <TabsContent value="architecture" className="mt-4">
          <ArchitecturePanel
            projectId={projectId}
            phase={phase}
            activePrdVersionId={selectedVersion?.id ?? null}
            onOpenRefinement={openRefinement}
          />
        </TabsContent>

        <TabsContent value="history" className="mt-4">
          <QuestionHistoryPanel
            projectId={projectId}
            prdVersions={prdVersions}
            isTabActive={activeTab === 'history'}
            onOpenRefinement={openRefinement}
          />
        </TabsContent>
      </Tabs>

      <ContextualRefinementPanel
        projectId={projectId}
        prdVersionId={refinement.prdVersionId}
        contextLabel={refinement.label}
        isOpen={refinement.isOpen}
        onClose={closeRefinement}
        onPrdUpdated={fetchVersions}
      />

      {/* Settings Dialog */}
      <Dialog open={showSettings} onOpenChange={setShowSettings}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle className="font-display">Project Settings</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div className="space-y-2">
              <label className="text-sm font-medium">Name</label>
              <Input value={editName} onChange={(e: React.ChangeEvent<HTMLInputElement>) => setEditName(e.target.value)} />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium">Description</label>
              <Textarea
                value={editDesc}
                onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => setEditDesc(e.target.value)}
                rows={3}
                className="resize-none"
              />
            </div>
            <div className="flex justify-end gap-2">
              <Button variant="ghost" onClick={() => setShowSettings(false)}>Cancel</Button>
              <Button onClick={handleSaveSettings} loading={saving}>Save</Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  )
}

'use client'

import { useCallback, useEffect, useState } from 'react'
import { Card, CardContent } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { MessageSquare, ArrowRight, HelpCircle, FileText, ListOrdered, RefreshCw } from 'lucide-react'
import { Stagger, StaggerItem } from '@/components/ui/animate'
import {
  QuestionHistoryListResponseSchema,
  type QuestionHistoryRow,
} from '@repo/contracts/questions/history'
import type { PrdVersionDTO } from '@repo/contracts/prd/prd-contracts'

interface QuestionHistoryPanelProps {
  projectId: string
  prdVersions: PrdVersionDTO[]
  isTabActive: boolean
  onOpenRefinement?: (payload: { label: string; prdVersionId: string | null }) => void
}

function formatDecisionWhen(createdAt: Date) {
  try {
    return createdAt.toLocaleString(undefined, {
      dateStyle: 'medium',
      timeStyle: 'short',
    })
  } catch {
    return ''
  }
}

function PrdVersionLabel({ prdVersionId, versions }: { prdVersionId: string | null; versions: PrdVersionDTO[] }) {
  if (!prdVersionId) {
    return <span className="text-xs text-muted-foreground">PRD: not linked to a version</span>
  }
  const match = versions.find((v) => v.id === prdVersionId)
  if (match) {
    return (
      <span className="text-xs text-muted-foreground">
        PRD version{' '}
        <span className="font-mono font-medium text-foreground">v{match.versionNumber}</span>
      </span>
    )
  }
  return (
    <span className="text-xs text-muted-foreground font-mono" title={prdVersionId}>
      PRD version (pending list)
    </span>
  )
}

function AvailableOptionsBlock({ row }: { row: QuestionHistoryRow }) {
  const ui = row.availableOptions
  if (!ui) {
    return (
      <div className="pl-6 text-xs text-muted-foreground italic">
        No structured options on file for this entry.
      </div>
    )
  }
  return (
    <div className="pl-6 space-y-2 rounded-md border border-border/60 bg-muted/30 p-3">
      <div className="flex items-center gap-1.5 text-xs font-medium text-foreground">
        <ListOrdered className="h-3.5 w-3.5" />
        Options presented
      </div>
      <p className="text-xs font-medium">{ui.title}</p>
      {ui.description ? <p className="text-xs text-muted-foreground">{ui.description}</p> : null}
      <ul className="space-y-1.5">
        {(ui.options ?? []).map((opt) => (
          <li key={opt.id} className="text-xs">
            <span className="font-medium">{opt.label}</span>
            {opt.description ? (
              <span className="text-muted-foreground"> — {opt.description}</span>
            ) : null}
          </li>
        ))}
      </ul>
      <p className="text-[11px] text-muted-foreground">
        {ui.allow_custom ? 'Custom answers allowed' : 'Fixed options'}
        {' · '}
        {ui.allow_not_sure ? '"Not sure" allowed' : 'No "not sure"'}
      </p>
    </div>
  )
}

export function QuestionHistoryPanel({
  projectId,
  prdVersions,
  isTabActive,
  onOpenRefinement,
}: QuestionHistoryPanelProps) {
  const [rows, setRows] = useState<QuestionHistoryRow[]>([])
  const [loading, setLoading] = useState(true)
  const [loadError, setLoadError] = useState<string | null>(null)

  const load = useCallback(async () => {
    setLoadError(null)
    setLoading(true)
    try {
      const res = await fetch(`/api/projects/${projectId}/questions`)
      if (res.status === 401) {
        setLoadError('You need to be signed in to view history.')
        setRows([])
        return
      }
      if (res.status === 404) {
        setLoadError('Project not found.')
        setRows([])
        return
      }
      if (!res.ok) {
        setLoadError('Could not load decision history.')
        setRows([])
        return
      }
      const raw: unknown = await res.json()
      const parsed = QuestionHistoryListResponseSchema.safeParse(raw)
      if (!parsed.success) {
        setLoadError('Received invalid data from the server. Try again or contact support.')
        setRows([])
        return
      }
      setRows(parsed.data)
    } catch {
      setLoadError('Network error. Check your connection and try again.')
      setRows([])
    } finally {
      setLoading(false)
    }
  }, [projectId])

  useEffect(() => {
    if (!isTabActive) return
    void load()
  }, [isTabActive, load])

  if (!isTabActive) {
    return null
  }

  if (loading) {
    return (
      <div className="space-y-3" aria-busy="true">
        {[1, 2, 3].map((i) => (
          <div key={i} className="h-28 min-h-[7rem] rounded-lg bg-muted animate-pulse" />
        ))}
      </div>
    )
  }

  if (loadError) {
    return (
      <Card className="border-destructive/40">
        <CardContent className="flex flex-col items-center justify-center gap-4 py-14 px-4 text-center">
          <p className="text-sm text-foreground">{loadError}</p>
          <Button type="button" variant="outline" className="min-h-11 min-w-[44px]" onClick={() => void load()}>
            <RefreshCw className="h-4 w-4 mr-2" />
            Retry
          </Button>
        </CardContent>
      </Card>
    )
  }

  if (rows.length === 0) {
    return (
      <Card className="border-dashed">
        <CardContent className="flex flex-col items-center justify-center py-16 px-4">
          <MessageSquare className="h-12 w-12 text-muted-foreground/30 mb-4" aria-hidden />
          <h3 className="font-display text-lg font-semibold mb-1">No decisions yet</h3>
          <p className="text-sm text-muted-foreground text-center max-w-sm">
            Structured decisions from clarification will appear here. Only you can see this log; it is not shown on
            shared links.
          </p>
        </CardContent>
      </Card>
    )
  }

  return (
    <div className="space-y-4">
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <p className="text-sm text-muted-foreground">
          {rows.length} decision{rows.length !== 1 ? 's' : ''} recorded
        </p>
        <Button
          type="button"
          variant="ghost"
          size="sm"
          className="min-h-11 w-full sm:w-auto self-start"
          onClick={() => void load()}
        >
          <RefreshCw className="h-4 w-4 mr-2" />
          Refresh
        </Button>
      </div>

      <Stagger staggerDelay={0.03}>
        <div className="space-y-3">
          {rows.map((q, i) => (
            <StaggerItem key={q.id}>
              <Card>
                <CardContent className="p-4 space-y-3">
                  <div className="flex flex-wrap items-start justify-between gap-2">
                    <div className="flex items-start gap-2 min-w-0 flex-1">
                      <HelpCircle className="h-4 w-4 text-primary mt-0.5 flex-shrink-0" aria-hidden />
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium text-foreground break-words">{q.structuredQuestion}</p>
                        <div className="flex flex-wrap gap-2 mt-1.5">
                          {q.questionType ? (
                            <Badge variant="secondary" className="text-xs">
                              {q.questionType}
                            </Badge>
                          ) : null}
                        </div>
                      </div>
                    </div>
                    <div className="flex flex-col items-end gap-1 flex-shrink-0 text-right">
                      {onOpenRefinement ? (
                        <Button
                          type="button"
                          variant="outline"
                          size="sm"
                          className="min-h-11 text-xs"
                          onClick={() =>
                            onOpenRefinement({
                              label: q.structuredQuestion,
                              prdVersionId: q.prdVersionId,
                            })
                          }
                        >
                          Revise
                        </Button>
                      ) : null}
                      <span className="text-xs text-muted-foreground font-mono">#{i + 1}</span>
                      <span className="text-[11px] text-muted-foreground">{formatDecisionWhen(q.createdAt)}</span>
                      {onOpenRefinement && q.founderAnswer ? (
                        <Button
                          type="button"
                          variant="ghost"
                          size="sm"
                          className="h-7 text-xs gap-1.5 mt-0.5"
                          onClick={() =>
                            onOpenRefinement({
                              label: `question: "${q.structuredQuestion}"`,
                              prdVersionId: q.prdVersionId,
                            })
                          }
                        >
                          <MessageSquare className="h-3 w-3" />
                          Revise
                        </Button>
                      ) : null}
                    </div>
                  </div>

                  <PrdVersionLabel prdVersionId={q.prdVersionId} versions={prdVersions} />

                  <AvailableOptionsBlock row={q} />

                  {q.founderAnswer ? (
                    <div className="flex items-start gap-2 pl-6 sm:pl-8">
                      <ArrowRight className="h-3.5 w-3.5 text-muted-foreground mt-0.5 flex-shrink-0" aria-hidden />
                      <div>
                        <p className="text-xs font-medium text-muted-foreground mb-0.5">Your answer</p>
                        <p className="text-sm text-foreground break-words">{q.founderAnswer}</p>
                      </div>
                    </div>
                  ) : null}

                  {q.optionalComment ? (
                    <div className="pl-6 sm:pl-8">
                      <p className="text-xs font-medium text-muted-foreground mb-0.5">Your comment</p>
                      <p className="text-sm text-foreground break-words">{q.optionalComment}</p>
                    </div>
                  ) : null}

                  {q.aiInterpretation ? (
                    <div className="bg-muted/50 rounded-lg p-2.5 ml-6 sm:ml-8">
                      <p className="text-xs text-muted-foreground break-words">
                        <span className="font-medium text-foreground/80">AI interpretation:</span> {q.aiInterpretation}
                      </p>
                    </div>
                  ) : null}

                  {q.prdImpact ? (
                    <div className="flex items-start gap-1.5 pl-6 sm:pl-8">
                      <FileText className="h-3.5 w-3.5 text-muted-foreground mt-0.5 flex-shrink-0" aria-hidden />
                      <div>
                        <p className="text-xs font-medium text-muted-foreground mb-0.5">PRD impact</p>
                        <p className="text-xs text-foreground break-words">{q.prdImpact}</p>
                      </div>
                    </div>
                  ) : null}
                </CardContent>
              </Card>
            </StaggerItem>
          ))}
        </div>
      </Stagger>
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { Badge } from '@/components/ui/badge'
import { QuestionCoverageReadinessScoreResponseSchema } from '@repo/contracts/questions/history'

interface ReadinessScoreBadgeProps {
  projectId: string
}

export function ReadinessScoreBadge({ projectId }: ReadinessScoreBadgeProps) {
  const [score, setScore] = useState<number>(0)
  const [sectionsCovered, setSectionsCovered] = useState<number>(0)
  const [phase, setPhase] = useState<'loading' | 'ready' | 'error'>('loading')

  useEffect(() => {
    const fetchScore = async () => {
      try {
        const res = await fetch(`/api/projects/${projectId}/readiness-score`)
        if (!res.ok) {
          setPhase('error')
          return
        }
        const raw = await res.json()
        const parsed = QuestionCoverageReadinessScoreResponseSchema.safeParse(raw)
        if (!parsed.success) {
          setPhase('error')
          return
        }
        setScore(parsed.data.score)
        setSectionsCovered(parsed.data.coveredSections.length)
        setPhase('ready')
      } catch {
        setPhase('error')
      }
    }
    void fetchScore()
  }, [projectId])

  if (phase === 'loading') return <Badge variant="outline">…</Badge>
  if (phase === 'error') return <Badge variant="outline">—</Badge>
  return (
    <Badge className="gap-1.5">
      <span>{score}% ready</span>
      <span className="opacity-80 font-normal">·</span>
      <span className="font-normal">{sectionsCovered}/8 sections</span>
    </Badge>
  )
}

'use client';

import { useCallback, useEffect, useMemo, useState } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { Button } from '@/components/ui/button';
import { FadeIn } from '@/components/ui/animate';
import { toast } from 'sonner';
import {
  ArrowLeft,
  BookOpen,
  CheckCircle,
  ExternalLink,
  Loader2,
  Plus,
  Sparkles,
  Trash2,
  Wand2,
} from 'lucide-react';
import {
  FeatureSplitListResponseSchema,
  type FeatureCluster,
  type FeatureSplitDTO,
} from '@repo/contracts/feature-split/feature-split';
import { PrdVersionListResponseSchema, type PrdVersionDTO } from '@repo/contracts/prd/prd-contracts';
import { GenerateUserStoriesResponseSchema } from '@repo/contracts/user-stories';
import { UserStoryCorpusSchema, type UserStoryCorpusDTO } from '@repo/contracts/user-stories';

interface UserStoriesWorkspaceProps {
  projectId: string;
  projectName: string;
}

type LineDraft = {
  id?: string;
  sortOrder: number;
  title: string;
  body: string;
  archivedAt?: string | null;
  draftMarker?: string | null;
};

function emptyLine(sortOrder: number): LineDraft {
  return { sortOrder, title: '', body: '' };
}

function confirmedSplitForVersion(splits: FeatureSplitDTO[], prdVersionId: string): FeatureSplitDTO | null {
  const match = splits.find((s) => s.status === 'confirmed' && s.sourcePrdVersionId === prdVersionId);
  return match ?? null;
}

function corpusToDrafts(corpus: UserStoryCorpusDTO): LineDraft[] {
  const active = corpus.lines.filter((l) => !l.archivedAt);
  const sorted = [...active].sort((a, b) => a.sortOrder - b.sortOrder);
  return sorted.map((l) => ({
    id: l.id,
    sortOrder: l.sortOrder,
    title: l.title,
    body: l.body,
    draftMarker: l.draftMarker,
  }));
}

export function UserStoriesWorkspace({ projectId, projectName }: UserStoriesWorkspaceProps) {
  const router = useRouter();
  const [prdVersions, setPrdVersions] = useState<PrdVersionDTO[]>([]);
  const [selectedVersionId, setSelectedVersionId] = useState<string | null>(null);
  const [splits, setSplits] = useState<FeatureSplitDTO[]>([]);
  const [selectedClusterId, setSelectedClusterId] = useState<string | null>(null);
  const [lines, setLines] = useState<LineDraft[]>([]);
  const [reviewReadyAt, setReviewReadyAt] = useState<Date | null>(null);
  const [hasPersistedCorpus, setHasPersistedCorpus] = useState(false);
  const [loading, setLoading] = useState(true);
  const [loadingCorpus, setLoadingCorpus] = useState(false);
  const [saving, setSaving] = useState(false);
  const [generatingTemplate, setGeneratingTemplate] = useState(false);
  const [generatingAi, setGeneratingAi] = useState(false);
  const [markingReady, setMarkingReady] = useState(false);
  const [lastGeneratedClusterId, setLastGeneratedClusterId] = useState<string | null>(null);
  /** When non-empty, template / AI actions run for these clusters (sequential). When empty, actions use `selectedClusterId` only. */
  const [batchClusterIds, setBatchClusterIds] = useState<string[]>([]);

  const fetchVersions = useCallback(async () => {
    try {
      const res = await fetch(`/api/projects/${projectId}/prd`);
      if (!res.ok) return;
      const raw = await res.json();
      const parsed = PrdVersionListResponseSchema.safeParse(raw);
      if (!parsed.success) return;
      setPrdVersions(parsed.data);
      if (parsed.data.length > 0 && !selectedVersionId) {
        setSelectedVersionId(parsed.data[0].id);
      }
    } catch {
      // network
    }
  }, [projectId, selectedVersionId]);

  const fetchSplitsForVersion = useCallback(
    async (prdVersionId: string) => {
      setLoading(true);
      try {
        const res = await fetch(
          `/api/projects/${projectId}/feature-split?sourcePrdVersionId=${encodeURIComponent(prdVersionId)}`
        );
        if (!res.ok) {
          setSplits([]);
          return;
        }
        const raw = await res.json();
        const parsed = FeatureSplitListResponseSchema.safeParse(raw);
        if (!parsed.success) {
          setSplits([]);
        } else {
          setSplits(parsed.data);
        }
      } catch {
        setSplits([]);
      } finally {
        setLoading(false);
      }
    },
    [projectId]
  );

  const fetchCorpus = useCallback(
    async (clusterId: string) => {
      setLoadingCorpus(true);
      try {
        const res = await fetch(
          `/api/projects/${projectId}/user-stories?featureSplitClusterId=${encodeURIComponent(clusterId)}`
        );
        if (res.status === 404) {
          setLines([emptyLine(0)]);
          setReviewReadyAt(null);
          setHasPersistedCorpus(false);
          return;
        }
        if (!res.ok) {
          toast.error('Could not load user stories');
          return;
        }
        const raw = await res.json();
        const parsed = UserStoryCorpusSchema.safeParse(raw);
        if (!parsed.success) {
          toast.error('Unexpected corpus response');
          return;
        }
        const corpus = parsed.data;
        setReviewReadyAt(corpus.reviewReadyAt);
        setHasPersistedCorpus(true);
        setLines(corpusToDrafts(corpus).length > 0 ? corpusToDrafts(corpus) : [emptyLine(0)]);
      } catch {
        toast.error('Network error loading stories');
      } finally {
        setLoadingCorpus(false);
      }
    },
    [projectId]
  );

  useEffect(() => {
    fetchVersions();
  }, [fetchVersions]);

  useEffect(() => {
    if (selectedVersionId) {
      setSelectedClusterId(null);
      setBatchClusterIds([]);
      setLines([]);
      fetchSplitsForVersion(selectedVersionId);
    }
  }, [selectedVersionId, fetchSplitsForVersion]);

  useEffect(() => {
    if (selectedClusterId) {
      fetchCorpus(selectedClusterId);
    }
  }, [selectedClusterId, fetchCorpus]);

  const confirmed = selectedVersionId ? confirmedSplitForVersion(splits, selectedVersionId) : null;
  const clusters: FeatureCluster[] = confirmed?.clusters ?? [];

  const batchSet = useMemo(() => new Set(batchClusterIds), [batchClusterIds]);

  const toggleBatchCluster = (clusterId: string) => {
    setBatchClusterIds((prev) =>
      prev.includes(clusterId) ? prev.filter((id) => id !== clusterId) : [...prev, clusterId]
    );
  };

  const selectAllClustersForBatch = () => {
    setBatchClusterIds(clusters.map((c) => c.id));
  };

  const clearBatchClusters = () => {
    setBatchClusterIds([]);
  };

  const generationTargets = (): string[] => {
    if (batchClusterIds.length > 0) return batchClusterIds;
    if (selectedClusterId) return [selectedClusterId];
    return [];
  };

  const handleLineChange = (index: number, field: keyof LineDraft, value: string | number) => {
    setLines((prev) => prev.map((line, i) => (i === index ? { ...line, [field]: value } : line)));
  };

  const handleAddLine = () => {
    setLines((prev) => [...prev, emptyLine(prev.length)]);
  };

  const handleRemoveLine = (index: number) => {
    setLines((prev) =>
      prev
        .filter((_, i) => i !== index)
        .map((line, i) => ({ ...line, sortOrder: i }))
    );
  };

  const buildSavePayload = (clusterId: string) => {
    const valid = lines.filter((l) => l.title.trim() && l.body.trim());
    return {
      featureSplitClusterId: clusterId,
      lines: valid.map((l) => ({
        ...(l.id ? { id: l.id } : {}),
        sortOrder: l.sortOrder,
        title: l.title.trim(),
        body: l.body.trim(),
        archivedAt: l.archivedAt ?? null,
        draftMarker: l.draftMarker ?? null,
      })),
    };
  };

  const applyCorpusResponse = (raw: unknown) => {
    const parsed = UserStoryCorpusSchema.safeParse(raw);
    if (!parsed.success) {
      toast.error('Unexpected response');
      return;
    }
    const corpus = parsed.data;
    setReviewReadyAt(corpus.reviewReadyAt);
    setHasPersistedCorpus(true);
    setLines(corpusToDrafts(corpus));
  };

  const handleSave = async () => {
    if (!selectedClusterId) return;
    const payload = buildSavePayload(selectedClusterId);
    if (payload.lines.length === 0) {
      toast.error('Add at least one story with title and description');
      return;
    }
    setSaving(true);
    try {
      const res = await fetch(`/api/projects/${projectId}/user-stories`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });
      const raw = await res.json();
      if (!res.ok) {
        toast.error(raw?.error ?? 'Save failed');
        return;
      }
      applyCorpusResponse(raw);
      toast.success('Stories saved');
    } catch {
      toast.error('Network error while saving');
    } finally {
      setSaving(false);
    }
  };

  const generateAiStoriesForCluster = async (
    clusterId: string,
    clusterLabel: string,
    onStoryProgress?: (corpus: UserStoryCorpusDTO) => void
  ): Promise<UserStoryCorpusDTO | null> => {
    const outlineRes = await fetch(`/api/projects/${projectId}/user-stories/generate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        featureSplitClusterId: clusterId,
        mode: 'ai',
        aiStep: 'outline',
      }),
    });
    const outlineRaw = await outlineRes.json();
    if (!outlineRes.ok) {
      if (outlineRes.status === 402) {
        toast.error('Insufficient credits for AI generation');
      } else {
        toast.error(outlineRaw?.error ?? 'Outline generation failed');
      }
      return null;
    }
    const outlineParsed = GenerateUserStoriesResponseSchema.safeParse(outlineRaw);
    if (!outlineParsed.success || outlineParsed.data.kind !== 'outline') {
      toast.error('Unexpected outline response');
      return null;
    }

    const { outlines, total } = outlineParsed.data;
    let existingLines: { sortOrder: number; title: string; body: string }[] = [];
    let lastCorpus: UserStoryCorpusDTO | null = null;

    for (let storyIndex = 0; storyIndex < outlines.length; storyIndex++) {
      toast.loading(`Story ${storyIndex + 1}/${total} — ${clusterLabel}`, { id: 'ai-story-gen' });
      const storyRes = await fetch(`/api/projects/${projectId}/user-stories/generate`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          featureSplitClusterId: clusterId,
          mode: 'ai',
          aiStep: 'story',
          outlines,
          outlineIndex: storyIndex,
          existingLines,
        }),
      });
      const storyRaw = await storyRes.json();
      if (!storyRes.ok) {
        toast.dismiss('ai-story-gen');
        if (storyRes.status === 402) {
          toast.error('Insufficient credits for AI generation');
        } else {
          const partial =
            existingLines.length > 0
              ? ` (${existingLines.length}/${total} stories saved before failure)`
              : '';
          toast.error((storyRaw?.error ?? 'Story generation failed') + partial);
        }
        return lastCorpus;
      }
      const storyParsed = GenerateUserStoriesResponseSchema.safeParse(storyRaw);
      if (!storyParsed.success || storyParsed.data.kind !== 'story') {
        toast.dismiss('ai-story-gen');
        toast.error(`Unexpected story response (${storyIndex + 1}/${total})`);
        return lastCorpus;
      }
      lastCorpus = storyParsed.data.corpus;
      existingLines = lastCorpus.lines
        .filter((l) => !l.archivedAt)
        .map((l) => ({
          sortOrder: l.sortOrder,
          title: l.title,
          body: l.body,
        }));
      onStoryProgress?.(lastCorpus);
    }

    toast.dismiss('ai-story-gen');
    return lastCorpus;
  };

  const handleGenerate = async (mode: 'template' | 'ai') => {
    const targets = generationTargets();
    if (targets.length === 0) {
      toast.error('Select a cluster to generate, or tick clusters for batch');
      return;
    }
    const setBusy = mode === 'template' ? setGeneratingTemplate : setGeneratingAi;
    setBusy(true);
    try {
      let rawForCurrentView: UserStoryCorpusDTO | null = null;
      const confirmedSplit = selectedVersionId
        ? confirmedSplitForVersion(splits, selectedVersionId)
        : null;
      const clusterById = new Map(
        (confirmedSplit?.clusters ?? []).map((c) => [c.id, c] as const)
      );

      for (let i = 0; i < targets.length; i++) {
        const clusterId = targets[i];
        const clusterLabel = clusterById.get(clusterId)?.label ?? 'cluster';

        if (mode === 'ai') {
          const corpus = await generateAiStoriesForCluster(
            clusterId,
            clusterLabel,
            selectedClusterId === clusterId ? applyCorpusResponse : undefined
          );
          if (corpus === null) return;
          if (selectedClusterId && clusterId === selectedClusterId) {
            rawForCurrentView = corpus;
          }
          continue;
        }

        const res = await fetch(`/api/projects/${projectId}/user-stories/generate`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ featureSplitClusterId: clusterId, mode: 'template' }),
        });
        const raw = await res.json();
        if (!res.ok) {
          toast.error(raw?.error ?? `Generation failed (cluster ${i + 1}/${targets.length})`);
          return;
        }
        const parsed = GenerateUserStoriesResponseSchema.safeParse(raw);
        if (!parsed.success || parsed.data.kind !== 'corpus') {
          toast.error(`Unexpected generate response (cluster ${i + 1}/${targets.length})`);
          return;
        }
        if (selectedClusterId && clusterId === selectedClusterId) {
          rawForCurrentView = parsed.data.corpus;
        }
      }
      if (rawForCurrentView != null) {
        applyCorpusResponse(rawForCurrentView);
      } else if (selectedClusterId && targets.includes(selectedClusterId)) {
        await fetchCorpus(selectedClusterId);
      }

      const primaryClusterId = selectedClusterId ?? targets[0];
      if (primaryClusterId) {
        setLastGeneratedClusterId(primaryClusterId);
      }

      const batchLabel = targets.length > 1 ? ` (${targets.length} clusters)` : '';
      const successMessage =
        mode === 'template'
          ? `Template stories generated${batchLabel}`
          : `AI drafts generated${batchLabel} — review and save`;
      toast.success(successMessage, {
        action: primaryClusterId
          ? {
              label: 'View stories',
              onClick: () =>
                router.push(
                  `/dashboard/projects/${projectId}/user-stories/${primaryClusterId}`
                ),
            }
          : undefined,
      });
    } catch {
      toast.error('Network error during generation');
    } finally {
      setBusy(false);
    }
  };

  const handleMarkReviewReady = async () => {
    if (!selectedClusterId || !hasPersistedCorpus) return;
    setMarkingReady(true);
    try {
      const res = await fetch(`/api/projects/${projectId}/user-stories/review-ready`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ featureSplitClusterId: selectedClusterId }),
      });
      const raw = await res.json();
      if (!res.ok) {
        toast.error(raw?.error ?? 'Could not mark review-ready');
        return;
      }
      applyCorpusResponse(raw);
      toast.success('Marked ready for review');
    } catch {
      toast.error('Network error');
    } finally {
      setMarkingReady(false);
    }
  };

  return (
    <div className="min-h-screen bg-background">
      <div className="mx-auto max-w-4xl px-4 py-8 sm:px-6 lg:px-8">
        <FadeIn>
          <div className="mb-6 flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
            <div>
              <Link
                href={`/dashboard/projects/${projectId}`}
                className="inline-flex items-center gap-2 text-sm text-muted-foreground hover:text-foreground mb-2 min-h-[44px] sm:min-h-0"
              >
                <ArrowLeft className="h-4 w-4" />
                Back to workspace
              </Link>
              <h1 className="text-2xl sm:text-3xl font-bold tracking-tight flex items-center gap-2">
                <BookOpen className="h-7 w-7 sm:h-8 sm:w-8 shrink-0 text-primary" />
                User stories
              </h1>
              <p className="text-muted-foreground text-sm sm:text-base mt-1">{projectName}</p>
            </div>
            <div className="flex flex-wrap gap-2">
              <Button variant="outline" asChild className="min-h-[44px]">
                <Link href={`/dashboard/projects/${projectId}/feature-split`}>Feature split</Link>
              </Button>
            </div>
          </div>

          <div className="rounded-lg border bg-card p-4 sm:p-6 space-y-6">
            <div className="space-y-2">
              <label htmlFor="prd-version" className="text-sm font-medium">
                PRD version
              </label>
              <select
                id="prd-version"
                className="w-full min-h-[44px] rounded-md border bg-background px-3 py-2 text-base"
                value={selectedVersionId ?? ''}
                onChange={(e) => setSelectedVersionId(e.target.value || null)}
              >
                <option value="" disabled>
                  Select version
                </option>
                {prdVersions.map((v) => (
                  <option key={v.id} value={v.id}>
                    {`Version ${v.versionNumber}`}
                  </option>
                ))}
              </select>
            </div>

            {!loading && selectedVersionId && !confirmed && (
              <div className="rounded-md border border-amber-500/30 bg-amber-500/5 p-4 text-sm">
                <p className="font-medium text-foreground">Confirm your feature split first</p>
                <p className="text-muted-foreground mt-1">
                  User stories are anchored to clusters from a confirmed split. Finish and confirm the split for this
                  PRD version, then return here.
                </p>
                <Button asChild className="mt-3 min-h-[44px]">
                  <Link href={`/dashboard/projects/${projectId}/feature-split`}>Open feature split</Link>
                </Button>
              </div>
            )}

            {confirmed && clusters.length > 0 && (
              <div className="space-y-2">
                <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
                  <span className="text-sm font-medium">Cluster</span>
                  <div className="flex flex-wrap gap-2">
                    <Button
                      type="button"
                      variant="ghost"
                      size="sm"
                      className="min-h-[44px]"
                      onClick={selectAllClustersForBatch}
                    >
                      Select all for batch
                    </Button>
                    <Button
                      type="button"
                      variant="ghost"
                      size="sm"
                      className="min-h-[44px]"
                      onClick={clearBatchClusters}
                      disabled={batchClusterIds.length === 0}
                    >
                      Clear batch
                    </Button>
                  </div>
                </div>
                <p className="text-xs text-muted-foreground">
                  Tick clusters to generate templates or AI drafts for several at once. With none ticked, generation
                  uses the cluster you open below.
                  {batchClusterIds.length > 0 ? ` (${batchClusterIds.length} in batch)` : null}
                </p>
                <div className="grid gap-2 sm:grid-cols-2">
                  {clusters.map((c) => {
                    const active = selectedClusterId === c.id;
                    const inBatch = batchSet.has(c.id);
                    const wasGenerated = lastGeneratedClusterId === c.id || (batchClusterIds.length > 1 && batchSet.has(c.id) && lastGeneratedClusterId !== null);
                    return (
                      <div
                        key={c.id}
                        className={`flex gap-2 rounded-lg border p-2 transition-colors ${
                          active ? 'border-primary bg-primary/5' : 'border-border'
                        } ${inBatch ? 'ring-1 ring-primary/30' : ''}`}
                      >
                        <label className="flex shrink-0 cursor-pointer items-center justify-center px-1 min-h-[44px] min-w-[44px]">
                          <input
                            type="checkbox"
                            className="h-5 w-5 rounded border-input"
                            checked={inBatch}
                            onChange={() => toggleBatchCluster(c.id)}
                            aria-label={`Include ${c.label} in batch generation`}
                          />
                        </label>
                        <div className="flex-1 min-w-0">
                          <button
                            type="button"
                            onClick={() => setSelectedClusterId(c.id)}
                            className="min-h-[44px] w-full text-left rounded-md px-1 py-1 hover:bg-muted/50"
                          >
                            <p className="font-medium text-sm">{c.label}</p>
                            <p className="text-xs text-muted-foreground line-clamp-2 mt-1">{c.valueLine}</p>
                          </button>
                          {wasGenerated && (
                            <Link
                              href={`/dashboard/projects/${projectId}/user-stories/${c.id}`}
                              className="inline-flex items-center gap-1 text-xs text-primary hover:underline px-1 pb-1"
                            >
                              <ExternalLink className="h-3 w-3" />
                              View stories
                            </Link>
                          )}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {selectedClusterId && (
              <>
                <div className="flex flex-col gap-2 sm:flex-row sm:flex-wrap sm:items-center border-t pt-4">
                  <Button
                    type="button"
                    variant="secondary"
                    disabled={generatingTemplate || loadingCorpus || generationTargets().length === 0}
                    onClick={() => handleGenerate('template')}
                    className="min-h-[44px] w-full sm:w-auto"
                  >
                    {generatingTemplate ? (
                      <Loader2 className="h-4 w-4 animate-spin" />
                    ) : (
                      <Sparkles className="h-4 w-4" />
                    )}
                    <span className="ml-2">From cluster (template)</span>
                  </Button>
                  <Button
                    type="button"
                    disabled={generatingAi || loadingCorpus || generationTargets().length === 0}
                    onClick={() => handleGenerate('ai')}
                    className="min-h-[44px] w-full sm:w-auto"
                  >
                    {generatingAi ? <Loader2 className="h-4 w-4 animate-spin" /> : <Wand2 className="h-4 w-4" />}
                    <span className="ml-2">Draft with AI</span>
                  </Button>
                  <Button
                    type="button"
                    variant="outline"
                    disabled={saving || loadingCorpus}
                    onClick={handleSave}
                    className="min-h-[44px] w-full sm:w-auto"
                  >
                    {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : null}
                    <span className={saving ? 'ml-2' : ''}>Save</span>
                  </Button>
                  <Button
                    type="button"
                    variant="outline"
                    disabled={markingReady || !hasPersistedCorpus || loadingCorpus}
                    onClick={handleMarkReviewReady}
                    className="min-h-[44px] w-full sm:w-auto"
                  >
                    {markingReady ? (
                      <Loader2 className="h-4 w-4 animate-spin" />
                    ) : (
                      <CheckCircle className="h-4 w-4" />
                    )}
                    <span className="ml-2">Mark review-ready</span>
                  </Button>
                </div>

                {reviewReadyAt && (
                  <p className="text-sm text-emerald-600 dark:text-emerald-400 flex items-center gap-2">
                    <CheckCircle className="h-4 w-4 shrink-0" />
                    Review-ready since {new Date(reviewReadyAt).toLocaleString()}
                  </p>
                )}

                {loadingCorpus ? (
                  <div className="flex justify-center py-12">
                    <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
                  </div>
                ) : (
                  <div className="space-y-4">
                    {lines.map((line, index) => (
                      <div key={line.id ?? `new-${index}`} className="rounded-lg border p-3 sm:p-4 space-y-3">
                        <div className="flex items-start justify-between gap-2">
                          <span className="text-xs font-medium text-muted-foreground">Story {index + 1}</span>
                          <Button
                            type="button"
                            variant="ghost"
                            size="icon"
                            className="shrink-0 min-h-[44px] min-w-[44px] text-destructive hover:text-destructive"
                            onClick={() => handleRemoveLine(index)}
                            aria-label="Remove story"
                          >
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </div>
                        <input
                          className="w-full min-h-[44px] rounded-md border bg-background px-3 py-2 text-base font-medium"
                          placeholder="Title"
                          value={line.title}
                          onChange={(e) => handleLineChange(index, 'title', e.target.value)}
                        />
                        <textarea
                          className="w-full min-h-[120px] rounded-md border bg-background px-3 py-2 text-base"
                          placeholder="As a … I want … so that …"
                          value={line.body}
                          onChange={(e) => handleLineChange(index, 'body', e.target.value)}
                        />
                      </div>
                    ))}
                    <Button type="button" variant="outline" onClick={handleAddLine} className="min-h-[44px] w-full sm:w-auto">
                      <Plus className="h-4 w-4" />
                      <span className="ml-2">Add story</span>
                    </Button>
                  </div>
                )}
              </>
            )}
          </div>
        </FadeIn>
      </div>
    </div>
  );
}

import { redirect } from 'next/navigation';
import { headers } from 'next/headers';
import { requireUser } from '@repo/auth/guards';
import { GetProjectUseCase } from '@application/project/get-project-usecase';
import { DrizzleProjectRepository } from '@infrastructure/persistence/project-repository';
import { FeatureSplitWorkspace } from '../_components/feature-split-workspace';

export default async function FeatureSplitPage({ params }: { params: { id: string } }) {
  const userResult = await requireUser(headers());
  if (userResult.isErr()) redirect('/sign-in');
  const userId = userResult.unwrap().id;

  const useCase = new GetProjectUseCase(new DrizzleProjectRepository());
  const result = await useCase.execute(params.id, userId);
  if (result.isErr()) redirect('/dashboard/projects');

  const project = result.unwrap();

  return (
    <FeatureSplitWorkspace
      projectId={project.id}
      projectName={project.name}
    />
  );
}

import { redirect } from 'next/navigation'
import { headers } from 'next/headers'
import { requireUser } from '@repo/auth/guards'
import { GetProjectUseCase } from '@application/project/get-project-usecase'
import { PrismaProjectRepository } from '@infrastructure/persistence/project-repository'
import { OwnerMilestonePromptProvider } from './_components/owner-milestone-prompt'

export default async function ProjectWorkspaceLayout({
  children,
  params,
}: {
