    private projectRepository: IProjectRepository,
    private prdRepository: IPrdRepository,
    private adrRepository: IAdrRepository
  ) {}

  async execute(
    projectId: string,
    userId: string
  ): Promise<Result<ReadinessScoreResponse, ApplicationError>> {
