import { UserId } from '@domain/user/user';

const makeValidUser = () => ({
  id: 'user-123',
  email: 'test@example.com',
  name: 'Test User',
  passwordHash: 'hashed-password',
  creditBalance: 0,
  graceUsed: false,
  starterCreditsGranted: false,
  createdAt: new Date(),
  updatedAt: new Date(),
});

const makeMockUserRepo = () => ({
  findByEmail: vi.fn(),
  findById: vi.fn(),
  create: vi.fn(),
  update: vi.fn(),
});

const makeMockCreditsRepo = () => ({
  getBalance: vi.fn(),
  addCredits: vi.fn(),
