/**
 * User Domain Service
 * 
 * Coordinates domain logic involving users.
 * Pure functions; no I/O; depends only on domain and Result.
 */

import { User, Email, UserId } from './user';
import { Result, ok, err } from '@repo/result';
import { ValidationError } from '@shared/errors/application-error';
import * as bcrypt from 'bcryptjs';

export class UserDomainService {
  /**
   * Hash a password for storage
   */
  static async hashPassword(password: string): Promise<Result<string, ValidationError>> {
    if (!password || password.length < 8) {
      return err(new ValidationError('Password must be at least 8 characters'));
    }

    try {
      const hash = await bcrypt.hash(password, 10);
      return ok(hash);
    } catch (error) {
      return err(new ValidationError('Failed to hash password'));
    }
  }

  /**
   * Verify password against hash
   */
  static async verifyPassword(password: string, hash: string): Promise<Result<boolean>> {
    try {
      const isValid = await bcrypt.compare(password, hash);
      return ok(isValid);
    } catch (error) {
      return ok(false);
    }
  }

  /**
   * Validate email format
   */
  static validateEmail(emailStr: string): Result<Email, ValidationError> {
    try {
      const email = new Email(emailStr);
      return ok(email);
    } catch (error) {
      return err(new ValidationError('Invalid email format'));
    }
  }

  /**
   * Create a new user entity
   */
  static createUser(
    id: string,
    email: Email,
    name: string,
    passwordHash: string
  ): User {
    return {
      id,
      email: email.value,
      name: name || null,
      passwordHash,
      creditBalance: 0,
      graceUsed: false,
      starterCreditsGranted: false,
      createdAt: new Date(),
      updatedAt: new Date(),
    };
  }
}

/**
 * AI wrapper for feature-split proposals.
 *
 * Calls the managed AI provider and validates the response against
 * FeatureSplitProposalSchema before returning. Keeps vendor isolation
 * inside infrastructure/ai/.
 */

import { FeatureSplitProposalSchema, FeatureSplitProposal } from '@repo/contracts/ai/feature-split-proposal';
import { Result, ok, err } from '@repo/result';
import { ApplicationError, ExternalServiceError } from '@shared/errors/application-error';
import { AiServiceError, callAI } from '@/lib/ai-service';
import { formatPrdContentForAi } from '@/lib/prd-content-for-ai';
import { createLogger } from '@shared/observability/logger';

const logger = createLogger({ service: 'FeatureSplitProposalAI' });

const SYSTEM_PROMPT = `You are Zedos, an expert product architect.
Given a PRD, extract a structured feature split — a list of coherent service clusters.

Each cluster represents one independently deliverable area. Output strictly valid JSON:
{
  "clusters": [
    {
      "sortOrder": 0,
      "label": "Short cluster name (max 500 chars)",
      "valueLine": "Single sentence: the user value this cluster delivers (max 2000 chars)",
      "boundaryCue": "Single sentence: what this cluster does NOT include (max 2000 chars)"
    }
  ]
}

Rules:
- Return at least 2 clusters and at most 32.
- Never return an empty clusters array.
- Clusters must be non-overlapping and collectively exhaustive for the PRD scope.
- Do not invent features not present in the PRD.
- Output only the JSON object, no extra text.`;

const RETRY_USER_SUFFIX = `IMPORTANT: Your previous answer was rejected because clusters was empty or invalid.
You MUST return at least 2 clusters with non-empty label, valueLine, and boundaryCue for each.`;

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

function mapAiFailure(error: unknown): ExternalServiceError {
  if (error instanceof AiServiceError) {
    if (error.status === 503) {
      return new ExternalServiceError('ai', 'AI provider is not configured on this server', 503);
    }
    if (error.status === 504) {
      return new ExternalServiceError(
        'ai',
        'AI request timed out — try again or shorten your PRD',
        504
      );
    }
    return new ExternalServiceError(
      'ai',
      'OpenAI could not generate a feature split — try again in a moment',
      502,
      { upstreamStatus: error.status }
    );
  }

  return new ExternalServiceError('ai', 'Feature split proposal failed', 502);
}

async function requestProposal(
  prdText: string,
  retryHint?: string
): Promise<Result<FeatureSplitProposal, ApplicationError>> {
  const userContent = retryHint
    ? `PRD content:\n${prdText}\n\n${retryHint}`
    : `PRD content:\n${prdText}`;

  const aiResponse = await callAI({
    messages: [
      { role: 'system', content: SYSTEM_PROMPT },
      { role: 'user', content: userContent },
    ],
    responseFormat: { type: 'json_object' },
    maxTokens: 4000,
    temperature: 0.3,
  });

  const raw = await aiResponse.json();
  const text: string = raw?.choices?.[0]?.message?.content ?? '{}';

  let parsed: unknown;
  try {
    parsed = JSON.parse(text);
  } catch {
    logger.error('AI returned non-JSON for feature split proposal', { text });
    return err(new ExternalServiceError('ai', 'AI returned invalid JSON for feature split'));
  }

  const validated = FeatureSplitProposalSchema.safeParse(parsed);
  if (validated.success) {
    return ok(validated.data);
  }

  const emptyClusters =
    isRecord(parsed) && Array.isArray(parsed.clusters) && parsed.clusters.length === 0;

  logger.error('AI proposal failed schema validation', {
    errors: validated.error.flatten(),
    emptyClusters,
  });

  if (emptyClusters) {
    return err(
      new ExternalServiceError(
        'ai',
        'AI returned no clusters for this PRD — enrich the PRD in the workspace or use “From PRD sections”',
        422
      )
    );
  }

  return err(new ExternalServiceError('ai', 'AI proposal did not match expected schema', 422));
}

export async function proposeFeatureSplit(
  prdContent: unknown
): Promise<Result<FeatureSplitProposal, ApplicationError>> {
  const prdText = formatPrdContentForAi(prdContent);

  try {
    const first = await requestProposal(prdText);
    if (first.isOk()) return first;

    if (first.error.statusCode !== 422) {
      return first;
    }

    const retry = await requestProposal(prdText, RETRY_USER_SUFFIX);
    return retry;
  } catch (error) {
    logger.error('Feature split AI call failed', error);
    return err(mapAiFailure(error));
  }
}

/**
 * AI wrapper for user-story draft generation — outline pass then one story per call.
 */

import {
  UserStoryAiOutlineListSchema,
  UserStoryAiSingleDraftSchema,
  type UserStoryAiDraftItem,
  type UserStoryAiOutlineItem,
} from '@repo/contracts';
import { Result, ok, err } from '@repo/result';
import { ApplicationError, ExternalServiceError } from '@shared/errors/application-error';
import { AiServiceError, callAI } from '@/lib/ai-service';
import { createLogger } from '@shared/observability/logger';

const logger = createLogger({ service: 'UserStoryDraftAI' });

function parsePositiveIntEnv(name: string, fallback: number): number {
  const raw = process.env[name]?.trim();
  if (!raw) return fallback;
  const n = Number.parseInt(raw, 10);
  return Number.isFinite(n) && n > 0 ? n : fallback;
}

const USER_STORY_DRAFT_OUTLINE_TIMEOUT_MS = parsePositiveIntEnv(
  'AI_USER_STORY_DRAFT_OUTLINE_TIMEOUT_MS',
  60_000
);
const USER_STORY_DRAFT_SINGLE_TIMEOUT_MS = parsePositiveIntEnv(
  'AI_USER_STORY_DRAFT_SINGLE_TIMEOUT_MS',
  90_000
);
const USER_STORY_DRAFT_MAX_STORIES = Math.min(
  32,
  parsePositiveIntEnv('AI_USER_STORY_DRAFT_MAX_STORIES', 12)
);

const OUTLINE_SYSTEM_PROMPT = `You are Zedos, a product manager. Given one feature cluster summary, list distinct user-visible behaviors as short titles only.

Output strictly valid JSON:
{ "outlines": [ { "title": "..." } ] }

Rules:
- 1 to 32 outlines.
- Each title names exactly ONE distinct user-visible behavior — something an end user can notice without knowing internals.
- Do not duplicate or near-duplicate intents; each title must differ.
- Titles: short verb phrases, max 2000 chars. No body text.
- Reflect only the cluster scope — do not invent unrelated scope.
- Output only the JSON object, no extra text.`;

const SINGLE_STORY_SYSTEM_PROMPT = `You are Zedos, a product manager. Expand ONE user-visible behavior into a full user story for a feature cluster.

Output strictly valid JSON:
{ "story": { "title": "...", "body": "...", "sortOrder": 0 } }

Rules:
- Exactly one story in "story".
- Title: short verb phrase for this behavior only, max 2000 chars (may match the outline title).
- Body: begin with "### User-visible outcome" (2–4 sentences); then 3–6 bullet acceptance criteria. Keep under 2500 characters total.
- sortOrder is optional.
- Do not merge unrelated behaviors; stay on the provided outline only.
- Body must end with observable acceptance signals.
- Output only the JSON object, no extra text.`;

function clusterPayload(input: { label: string; valueLine: string; boundaryCue: string }): string {
  return JSON.stringify(
    {
      label: input.label,
      valueLine: input.valueLine,
      boundaryCue: input.boundaryCue,
    },
    null,
    2
  );
}

async function parseAiJsonContent<T>(
  raw: unknown,
  label: string,
  validate: (parsed: unknown) => { success: true; data: T } | { success: false }
): Promise<Result<T, ApplicationError>> {
  const text: string =
    typeof raw === 'object' && raw !== null && 'choices' in raw
      ? String((raw as { choices?: { message?: { content?: string } }[] }).choices?.[0]?.message?.content ?? '{}')
      : '{}';

  let parsed: unknown;
  try {
    parsed = JSON.parse(text);
  } catch {
    logger.error(`AI returned non-JSON for ${label}`, { text });
    return err(new ExternalServiceError('AI', `AI returned invalid JSON for ${label}`));
  }

  const validated = validate(parsed);
  if (!validated.success) {
    logger.error(`AI ${label} failed schema validation`, { parsed });
    return err(new ExternalServiceError('AI', `AI ${label} did not match expected schema`));
  }

  return ok(validated.data);
}

export async function draftOutlinesForCluster(input: {
  label: string;
  valueLine: string;
  boundaryCue: string;
}): Promise<Result<UserStoryAiOutlineItem[], ApplicationError>> {
  const aiResponse = await callAI({
    messages: [
      { role: 'system', content: OUTLINE_SYSTEM_PROMPT },
      { role: 'user', content: `Feature cluster:\n${clusterPayload(input)}` },
    ],
    responseFormat: { type: 'json_object' },
    maxTokens: 2000,
    temperature: 0.25,
    timeoutMs: USER_STORY_DRAFT_OUTLINE_TIMEOUT_MS,
  });

  const raw = await aiResponse.json();
  const listResult = await parseAiJsonContent(raw, 'user story outlines', (parsed) => {
    const validated = UserStoryAiOutlineListSchema.safeParse(parsed);
    return validated.success
      ? { success: true as const, data: validated.data.outlines }
      : { success: false as const };
  });
  if (listResult.isErr()) return listResult;

  const capped = listResult.unwrap().slice(0, USER_STORY_DRAFT_MAX_STORIES);
  if (capped.length === 0) {
    return err(new ExternalServiceError('AI', 'AI returned no user story outlines'));
  }

  return ok(capped);
}

export async function draftSingleStoryForCluster(
  input: { label: string; valueLine: string; boundaryCue: string },
  outline: UserStoryAiOutlineItem,
  sortOrder: number
): Promise<Result<UserStoryAiDraftItem, ApplicationError>> {
  const aiResponse = await callAI({
    messages: [
      { role: 'system', content: SINGLE_STORY_SYSTEM_PROMPT },
      {
        role: 'user',
        content: [
          `Feature cluster:\n${clusterPayload(input)}`,
          `Outline to expand (sortOrder ${sortOrder}):\n${JSON.stringify(outline, null, 2)}`,
        ].join('\n\n'),
      },
    ],
    responseFormat: { type: 'json_object' },
    maxTokens: 1400,
    temperature: 0.35,
    timeoutMs: USER_STORY_DRAFT_SINGLE_TIMEOUT_MS,
  });

  const raw = await aiResponse.json();
  const storyResult = await parseAiJsonContent(raw, 'single user story', (parsed) => {
    const validated = UserStoryAiSingleDraftSchema.safeParse(parsed);
    return validated.success
      ? { success: true as const, data: validated.data.story }
      : { success: false as const };
  });
  if (storyResult.isErr()) return storyResult;

  const story = storyResult.unwrap();
  return ok({
    title: story.title,
    body: story.body,
    sortOrder: story.sortOrder ?? sortOrder,
  });
}

/**
 * HTTP-layer helpers for credit checks/consumption via composed use cases.
 * Used by App Router API routes instead of `@/lib/credits`.
 */

import type { OperationType as DomainOperationType } from '@domain/credits/credits';
import type { CreditCheckResult as DomainCreditCheckResult } from '@domain/credits/credits';
import { Result, ok, err } from '@repo/result';
import { ApplicationError, NotFoundError } from '@shared/errors/application-error';
