      "open_questions": []
    }
  ]
}

Rules:
- Fill in as much detail as possible from the clarification history
- Mark confidence level for each section based on how much was discussed
- List open questions where clarification is still needed
- Be specific and actionable, not generic
- Use the founder's own language and decisions

Respond with raw JSON only. No markdown, no code blocks.`

type FlowError = { ok: false; status: number; error: string; details?: unknown }
type FlowSuccess = {
  ok: true
  stream: ReadableStream
}
type GeneratePrdStreamResult = FlowError | FlowSuccess

type GeneratePrdStreamInput = {
  projectId: string
  userId: string
}

export async function generatePrdStreamForProject(
  input: GeneratePrdStreamInput
): Promise<GeneratePrdStreamResult> {
  const [project] = await db
    .select()
    .from(projects)
    .where(and(eq(projects.id, input.projectId), eq(projects.userId, input.userId)))
    .limit(1)

  if (!project) return { ok: false, status: 404, error: 'Project not found' }

  const creditCheck = await checkCredits(input.userId, 'prd_generation')
  if (!creditCheck.allowed) {
    return {
      ok: false,
      status: 402,
      error: 'insufficient_credits',
      details: {
        message: creditCheck.reason,
        balance: creditCheck.currentBalance,
        cost: creditCheck.cost,
      },
    }
  }

  const history = await db
    .select()
    .from(questionHistory)
    .where(eq(questionHistory.projectId, input.projectId))
    .orderBy(asc(questionHistory.createdAt))

  const [lastVersion] = await db
    .select({ versionNumber: prdVersions.versionNumber, content: prdVersions.content })
    .from(prdVersions)
    .where(eq(prdVersions.projectId, input.projectId))
    .orderBy(desc(prdVersions.versionNumber))
    .limit(1)

  const nextVersionNumber = (lastVersion?.versionNumber ?? 0) + 1
  const isUpdate = nextVersionNumber > 1

  const clarificationSummary = history
    .map((q) => `Q: ${q.structuredQuestion}\nA: ${q.founderAnswer ?? 'Not answered'}\nImpact: ${q.prdImpact ?? 'General'}`)
    .join('\n\n')

  const messages = [
    { role: 'system' as const, content: PRD_SYSTEM_PROMPT },
    {
      role: 'user' as const,
      content: `Project: "${project.name}"\nDescription: ${project.description ?? 'Not provided'}\n\nVersion: ${nextVersionNumber}${isUpdate ? ` (updating from v${nextVersionNumber - 1})` : ' (initial)'}\n\nClarification History:\n${clarificationSummary || 'No clarifications yet - generate a basic PRD framework based on the project name and description.'}`,
    },
  ]

  if (isUpdate && lastVersion?.content) {
    messages.push({
      role: 'user' as const,
      content: `Previous PRD (v${lastVersion.versionNumber}):\n${JSON.stringify(lastVersion.content)}\n\nUpdate this PRD with the new clarifications while preserving existing decisions.`,
    })
  }

  const aiResponse = await callAI({
    messages,
    stream: true,
    maxTokens: 6000,
    temperature: 0.5,
    responseFormat: { type: 'json_object' },
  })

  const stream = createBufferedStreamingResponse(aiResponse, async (result: string) => {
    try {
      const parsed = JSON.parse(result) as unknown
      const validated = GeneratePrdAiResponseSchema.safeParse(parsed)
      if (!validated.success) {
        logger.error('Generate PRD AI response validation failed', validated.error.flatten())
        return
      }
      await deductCredits(input.userId, 'prd_generation', { projectId: input.projectId })
      const prdInsert: PrdVersionInsert = {
        projectId: input.projectId,
        versionNumber: nextVersionNumber,
        content: validated.data,
        status: 'generated',
      }
      await db.insert(prdVersions).values(prdInsert)
    } catch (error: unknown) {
      logger.error('Failed to save PRD version', error)
    }
  })

  return { ok: true, stream }
}

/**
 * In-Process Event Bus
 * 
 * Enables domain event publishing and subscription within a single process.
 * Used for cross-aggregate communication (e.g., when a PRD is generated, emit event for archiving/cleanup).
 * In-memory only; events are lost on process restart. Not a persistent event store.
 * 
 * Future: Can be swapped with persistent event store (Kafka, EventStoreDB) by implementing this interface.
 */

export interface DomainEvent {
  id: string;
  type: string;
  aggregateId: string; // projectId, userId, etc.
  timestamp: Date;
  data: Record<string, any>;
}

export type EventHandler<T extends DomainEvent = DomainEvent> = (event: T) => void | Promise<void>;

export class EventBus {
  private handlers: Map<string, EventHandler<any>[]> = new Map();

  subscribe<T extends DomainEvent = DomainEvent>(eventType: string, handler: EventHandler<T>): void {
    if (!this.handlers.has(eventType)) {
      this.handlers.set(eventType, []);
    }
    this.handlers.get(eventType)!.push(handler as EventHandler<any>);
  }

  async publish<T extends DomainEvent = DomainEvent>(event: T): Promise<void> {
    const handlers = this.handlers.get(event.type) || [];
    await Promise.all(handlers.map((h) => h(event)));
  }

  unsubscribe(eventType: string, handler: EventHandler<any>): void {
    const handlers = this.handlers.get(eventType);
    if (handlers) {
      const index = handlers.indexOf(handler);
      if (index > -1) {
        handlers.splice(index, 1);
      }
    }
  }

  clear(): void {
    this.handlers.clear();
  }
}

export const eventBus = new EventBus();

import { NextResponse } from 'next/server';
import { ApplicationError } from '@shared/errors/application-error';

export function applicationErrorJson(error: ApplicationError): {
  error: string;
  details: ApplicationError['details'];
} {
  return {
    error: error.message,
    details: error.details,
  };
}

export function toNextErrorResponse(error: ApplicationError): NextResponse {
  return NextResponse.json(applicationErrorJson(error), { status: error.statusCode });
}

export function catchUnknownError(
  error: unknown,
  fallbackMessage: string
): NextResponse {
  const message = error instanceof Error && error.message.length > 0 ? error.message : fallbackMessage;
  console.error(fallbackMessage, error);
  return NextResponse.json({ error: fallbackMessage }, { status: 500 });
}

import { describe, it, expect } from 'vitest';
import { ok, err, Ok, Err, collect } from './result';

describe('Result<T,E>', () => {
  describe('Ok', () => {
    it('isOk returns true', () => {
      const r = ok(42);
      expect(r.isOk()).toBe(true);
      expect(r.isErr()).toBe(false);
    });

    it('unwrap returns value', () => {
      expect(ok('hello').unwrap()).toBe('hello');
    });

    it('map transforms value', () => {
      const r = ok(5).map((x) => x * 2);
      expect(r.unwrap()).toBe(10);
    });

    it('flatMap chains results', () => {
      const r = ok(5).flatMap((x) => ok(x + 1));
      expect(r.unwrap()).toBe(6);
    });

    it('flatMap propagates error', () => {
      const r = ok(5).flatMap(() => err(new Error('fail')));
      expect(r.isErr()).toBe(true);
    });

    it('getOrElse returns value', () => {
      expect(ok(10).getOrElse(0)).toBe(10);
    });

    it('mapErr is no-op for Ok', () => {
      const r = ok(1).mapErr(() => new Error('mapped'));
      expect(r.isOk()).toBe(true);
      expect(r.unwrap()).toBe(1);
    });
  });

  describe('Err', () => {
    it('isErr returns true', () => {
      const r = err(new Error('bad'));
      expect(r.isErr()).toBe(true);
      expect(r.isOk()).toBe(false);
    });

    it('unwrap throws', () => {
      expect(() => err(new Error('bad')).unwrap()).toThrow('bad');
    });

    it('getOrElse returns fallback', () => {
      const r = err(new Error('bad')) as any;
      expect(r.getOrElse(99)).toBe(99);
    });

    it('map is no-op for Err', () => {
      const r = err(new Error('x')).map(() => 42);
      expect(r.isErr()).toBe(true);
    });

    it('mapErr transforms error', () => {
      const r = err(new Error('a')).mapErr(() => new Error('b'));
      expect(r.isErr()).toBe(true);
      expect(() => r.unwrap()).toThrow('b');
    });

    it('flatMap propagates error', () => {
      const r = err(new Error('nope')).flatMap(() => ok(1));
      expect(r.isErr()).toBe(true);
    });
  });

  describe('collect', () => {
    it('returns Ok array when all Ok', () => {
      const r = collect([ok(1), ok(2), ok(3)]);
      expect(r.isOk()).toBe(true);
      expect(r.unwrap()).toEqual([1, 2, 3]);
    });

    it('returns first Err when any fails', () => {
      const r = collect([ok(1), err(new Error('fail')), ok(3)]);
      expect(r.isErr()).toBe(true);
    });

    it('returns Ok empty array for empty input', () => {
      const r = collect([]);
      expect(r.isOk()).toBe(true);
      expect(r.unwrap()).toEqual([]);
    });
  });
});

/**
 * Result<T, E> type - explicit error handling without exceptions across boundaries.
 * Based on Rust's Result and Railway-Oriented Programming (ROP) patterns.
 * 
 * - Ok(value): Represents successful computation
 * - Err(error): Represents failed computation
 * 
 * Enforces explicit error handling and prevents unhandled exceptions from crossing layer boundaries.
 */

export type Result<T, E = Error> = Ok<T> | Err<E>;

export class Ok<T> {
  constructor(readonly value: T) {}

  isOk(): this is Ok<T> {
    return true;
  }

  isErr(): this is Err<never> {
    return false;
  }

  map<U>(fn: (value: T) => U): Result<U> {
    return new Ok(fn(this.value));
  }

  mapErr<E2>(fn: (err: never) => E2): Result<T, E2> {
    return this as any;
  }

  flatMap<U, E2 = Error>(fn: (value: T) => Result<U, E2>): Result<U, E2> {
    return fn(this.value);
  }

  getOrElse(defaultValue: T): T {
    return this.value;
  }

  unwrap(): T {
    return this.value;
  }
}

export class Err<E = Error> {
  constructor(readonly error: E) {}

  isOk(): this is Ok<never> {
    return false;
  }

  isErr(): this is Err<E> {
    return true;
  }

  map<U>(fn: (value: never) => U): Result<U, E> {
    return this as any;
  }

  mapErr<E2>(fn: (err: E) => E2): Result<never, E2> {
    return new Err(fn(this.error));
  }

  flatMap<U, E2 = Error>(fn: (value: never) => Result<U, E2>): Result<U, E | E2> {
    return this as any;
  }

  getOrElse(defaultValue: any): any {
    return defaultValue;
  }

  unwrap(): never {
    throw this.error;
  }
}

// Utility functions
export const ok = <T>(value: T): Result<T> => new Ok(value);
export const err = <E = Error>(error: E): Result<never, E> => new Err(error);

/**
 * Combinator: collect results and return first error or array of successes
 */
export const collect = <T, E = Error>(results: Result<T, E>[]): Result<T[], E | Error> => {
  const values: T[] = [];
  for (const result of results) {
    if (result.isErr()) {
      return result as any;
    }
    values.push((result as Ok<T>).unwrap());
  }
  return ok(values) as any;
};
